// src/app/state.js
function createDefaultCeilingLayout() {
  return {
    enabled: false,
    tileSize: 0.6,
    xAnchorMode: "symmetric",
    yAnchorMode: "symmetric",
    luminaireTiles: new Set()
  };
}

function createAppState() {
  return {
    latestReportState: null,
    ceilingLayout: createDefaultCeilingLayout()
  };
}

function setLatestReportState(state, latestReportState) {
  state.latestReportState = latestReportState;
}

function updateCeilingLayout(state, patch) {
  state.ceilingLayout = {
    ...state.ceilingLayout,
    ...patch,
    luminaireTiles:
      patch.luminaireTiles instanceof Set
        ? patch.luminaireTiles
        : new Set(state.ceilingLayout.luminaireTiles)
  };
}

function toggleCeilingLuminaireTile(state, tileKey) {
  const nextLuminaireTiles = new Set(state.ceilingLayout.luminaireTiles);

  if (nextLuminaireTiles.has(tileKey)) {
    nextLuminaireTiles.delete(tileKey);
  } else {
    nextLuminaireTiles.add(tileKey);
  }

  updateCeilingLayout(state, { luminaireTiles: nextLuminaireTiles });
}

function clearCeilingLuminaires(state) {
  updateCeilingLayout(state, { luminaireTiles: new Set() });
}

function createSelectedReportOptionKeys(items) {
  return items.map((item) => item.key);
}

function getSelectableReportOptions(reportState) {
  if (!reportState) {
    return [];
  }

  if (reportState.kind === "uniformity-ok") {
    return reportState.candidates || [];
  }

  return [];
}

function getSelectedReportOptions(reportState) {
  const selectableOptions = getSelectableReportOptions(reportState);
  if (selectableOptions.length === 0) {
    return [];
  }

  const selectedKeys = new Set(
    reportState.selectedOptionKeys?.length
      ? reportState.selectedOptionKeys
      : createSelectedReportOptionKeys(selectableOptions)
  );

  return selectableOptions.filter((item) => selectedKeys.has(item.key));
}

function toggleLatestReportOptionSelection(state, optionKey, selected) {
  const reportState = state.latestReportState;
  const selectableOptions = getSelectableReportOptions(reportState);
  if (!reportState || selectableOptions.length === 0) {
    return;
  }

  const selectableKeys = selectableOptions.map((item) => item.key);
  if (!selectableKeys.includes(optionKey)) {
    return;
  }

  const nextSelectedKeys = new Set(
    reportState.selectedOptionKeys?.length
      ? reportState.selectedOptionKeys
      : createSelectedReportOptionKeys(selectableOptions)
  );

  if (selected) {
    nextSelectedKeys.add(optionKey);
  } else {
    nextSelectedKeys.delete(optionKey);
  }

  reportState.selectedOptionKeys = selectableKeys.filter((key) => nextSelectedKeys.has(key));
}

function resetState(state) {
  state.latestReportState = null;
  state.ceilingLayout = createDefaultCeilingLayout();
}

// src/core/messages.js
function buildHeightDiameterRequirementMessage(room, modes, realDiameters) {
  const maxRealDiameter = realDiameters.length > 0 ? realDiameters[realDiameters.length - 1] : null;
  if (!room || !Number.isFinite(room.height) || !Number.isFinite(maxRealDiameter) || modes.length === 0) {
    return "";
  }

  const blockedModes = modes
    .map((mode) => ({
      mode,
      minimumDiameter: room.height / (2 + mode.factor)
    }))
    .filter((entry) => entry.minimumDiameter > maxRealDiameter + EPS);

  if (blockedModes.length === 0) {
    return "";
  }

  const requiredText = joinWithOr(
    blockedModes.map(
      (entry) => `${formatMeters(entry.minimumDiameter)} en ${entry.mode.label.toLowerCase()}`
    )
  );

  return `La base BRASSE II embarquee s'arrete a ${formatMeters(maxRealDiameter)} (${formatDiameterCm(maxRealDiameter)} cm). Avec ${formatMeters(room.height)} de HSP, il faudrait ici en theorie au moins ${requiredText}.`;
}

function getCandidateWarnings(candidate) {
  const warnings = [];
  if (!candidate.recommendedSmallHeightMet && candidate.fanClass === "small") {
    warnings.push(
      "La recommandation d'aisance sur la hauteur sous pales (> 1,4 D) n'est pas atteinte."
    );
  }
  if (candidate.mountMode.id === "low-profile") {
    warnings.push(candidate.mountMode.penaltyText);
  }
  return warnings;
}

// src/core/brasse2.js
/**
 * Retourne tous les modeles BRASSE II compatibles avec les diametres admissibles
 * d'une option de calepinage.
 */
function getBrasse2ModelsForCandidate(candidate, brasse2Models) {
  const optionsByDiameterCm = new Map(
    candidate.compatibleRealDiameters.map((option) => [Math.round(option.diameter * 100), option])
  );

  return brasse2Models
    .filter((model) => optionsByDiameterCm.has(model.diameterCm))
    .map((model) => ({
      ...model,
      compatibleOption: optionsByDiameterCm.get(model.diameterCm),
      mountFits:
        model.ceilingDistanceCm <=
        candidate.mountMode.factor * optionsByDiameterCm.get(model.diameterCm).diameter * 100 + 0.5,
      mountDeltaCm: Number(
        (
          candidate.mountMode.factor * optionsByDiameterCm.get(model.diameterCm).diameter * 100 -
          model.ceilingDistanceCm
        ).toFixed(1)
      ),
      isSelectedDiameter: Math.abs(model.diameterCm - Math.round(candidate.diameter * 100)) <= 0.5
    }));
}

function pickBestModel(models, comparator) {
  return [...models].sort(comparator)[0] || null;
}

function compareComfort(a, b) {
  if (Math.abs(b.ceDirDeboutMax - a.ceDirDeboutMax) > EPS) {
    return b.ceDirDeboutMax - a.ceDirDeboutMax;
  }
  if (Math.abs(a.lwaMaxDbA - b.lwaMaxDbA) > EPS) {
    return a.lwaMaxDbA - b.lwaMaxDbA;
  }
  return a.powerMaxW - b.powerMaxW;
}

function compareEfficiency(a, b) {
  if (Math.abs(b.cfeDirDeboutMax - a.cfeDirDeboutMax) > EPS) {
    return b.cfeDirDeboutMax - a.cfeDirDeboutMax;
  }
  if (Math.abs(a.lwaMaxDbA - b.lwaMaxDbA) > EPS) {
    return a.lwaMaxDbA - b.lwaMaxDbA;
  }
  return b.ceDirDeboutMax - a.ceDirDeboutMax;
}

function compareAcoustics(a, b) {
  if (Math.abs(a.lwaMaxDbA - b.lwaMaxDbA) > EPS) {
    return a.lwaMaxDbA - b.lwaMaxDbA;
  }
  if (Math.abs(b.ceDirDeboutMax - a.ceDirDeboutMax) > EPS) {
    return b.ceDirDeboutMax - a.ceDirDeboutMax;
  }
  return a.powerMaxW - b.powerMaxW;
}

function compareCoverage(a, b) {
  const coverageA = Number.isFinite(a.compatibleOption?.coverageFactor)
    ? a.compatibleOption.coverageFactor
    : -Infinity;
  const coverageB = Number.isFinite(b.compatibleOption?.coverageFactor)
    ? b.compatibleOption.coverageFactor
    : -Infinity;

  if (Math.abs(coverageB - coverageA) > EPS) {
    return coverageB - coverageA;
  }
  return compareComfort(a, b);
}

function modelMountLabel(model) {
  return model.mountFits
    ? "Distance plafond/BA compatible"
    : "Distance plafond/BA a verifier";
}

function buildModelPicks(models) {
  return [
    { title: "FCC", model: pickBestModel(models, compareCoverage) },
    { title: "Confort", model: pickBestModel(models, compareComfort) },
    { title: "Efficacite", model: pickBestModel(models, compareEfficiency) },
    { title: "Acoustique", model: pickBestModel(models, compareAcoustics) }
  ].filter((pick) => Boolean(pick.model));
}

function getReportModelHighlights(candidate, brasse2Models) {
  return buildModelPicks(getBrasse2ModelsForCandidate(candidate, brasse2Models));
}

// src/core/catalog.js
function compareCatalogIdentity(a, b) {
  const brandDiff = String(a.brand).localeCompare(String(b.brand), "fr", {
    sensitivity: "base"
  });
  if (brandDiff !== 0) {
    return brandDiff;
  }
  const modelDiff = String(a.model).localeCompare(String(b.model), "fr", {
    sensitivity: "base"
  });
  if (modelDiff !== 0) {
    return modelDiff;
  }
  return String(a.id).localeCompare(String(b.id), "fr", {
    sensitivity: "base",
    numeric: true
  });
}

const CATALOG_SORTS = {
  "diameter-asc": (a, b) => a.diameterCm - b.diameterCm || compareCatalogIdentity(a, b),
  "diameter-desc": (a, b) => b.diameterCm - a.diameterCm || compareCatalogIdentity(a, b),
  comfort: (a, b) => compareComfort(a, b) || compareCatalogIdentity(a, b),
  efficiency: (a, b) => compareEfficiency(a, b) || compareCatalogIdentity(a, b),
  acoustics: (a, b) => compareAcoustics(a, b) || compareCatalogIdentity(a, b),
  power: (a, b) => a.powerMaxW - b.powerMaxW || compareCatalogIdentity(a, b),
  brand: compareCatalogIdentity
};

function normalizeCatalogSearch(value) {
  return String(value || "")
    .trim()
    .toLocaleLowerCase("fr")
    .normalize("NFD")
    .replaceAll(/\p{Diacritic}/gu, "");
}

function getCatalogFilterOptions(brasse2Models) {
  return {
    brands: [...new Set(brasse2Models.map((model) => model.brand))].sort((a, b) =>
      String(a).localeCompare(String(b), "fr", { sensitivity: "base" })
    ),
    diameters: [...new Set(brasse2Models.map((model) => model.diameterCm))].sort((a, b) => a - b),
    motors: [...new Set(brasse2Models.map((model) => model.motor))].sort(),
    fixations: [...new Set(brasse2Models.map((model) => model.fixation))].sort((a, b) =>
      String(a).localeCompare(String(b), "fr", { sensitivity: "base" })
    )
  };
}

function getCatalogActiveFilterLabels(filters) {
  const labels = [];
  if (filters.search) {
    labels.push(`recherche: ${filters.search}`);
  }
  if (filters.brand) {
    labels.push(`marque: ${filters.brand}`);
  }
  if (Number.isFinite(filters.diameterCm)) {
    labels.push(`diametre: ${filters.diameterCm} cm`);
  }
  if (filters.motor) {
    labels.push(`moteur: ${filters.motor}`);
  }
  if (filters.fixation) {
    labels.push(`fixation: ${filters.fixation}`);
  }
  return labels;
}

function getFilteredCatalogModels(brasse2Models, filters) {
  const search = normalizeCatalogSearch(filters.search);
  const comparator = CATALOG_SORTS[filters.sort] || CATALOG_SORTS["diameter-asc"];

  return brasse2Models
    .filter((model) => {
      if (search) {
        const haystack = normalizeCatalogSearch(
          `${model.id} ${model.brand} ${model.model} ${model.motor} ${model.fixation} ${model.diameterCm}`
        );
        if (!haystack.includes(search)) {
          return false;
        }
      }

      if (filters.brand && model.brand !== filters.brand) {
        return false;
      }
      if (Number.isFinite(filters.diameterCm) && model.diameterCm !== filters.diameterCm) {
        return false;
      }
      if (filters.motor && model.motor !== filters.motor) {
        return false;
      }
      if (filters.fixation && model.fixation !== filters.fixation) {
        return false;
      }
      return true;
    })
    .sort(comparator);
}

// src/core/ceilingGrid.js
const CEILING_TILE_SIZE = 0.6;
const CEILING_ANCHOR_MODES = ["min_side", "max_side", "symmetric"];

function ceilingGridRound(value) {
  return Number(value.toFixed(6));
}

function buildCeilingAxisTiles(length, tileSize, anchorMode, axisName) {
  const safeLength = Math.max(0, length);
  const fullTileCount = Math.floor((safeLength + EPS) / tileSize);
  const rawRemainder = safeLength - fullTileCount * tileSize;
  const remainder = rawRemainder > EPS ? rawRemainder : 0;
  const tiles = [];
  let cursor = 0;

  const pushTile = (min, max, kind) => {
    if (max - min <= EPS) {
      return;
    }

    tiles.push({
      axis: axisName,
      index: tiles.length,
      key: `${axisName}-${tiles.length}`,
      min: ceilingGridRound(min),
      max: ceilingGridRound(max),
      size: ceilingGridRound(max - min),
      center: ceilingGridRound((min + max) / 2),
      isCut: kind === "cut"
    });
  };

  if (remainder === 0 || anchorMode === "min_side") {
    for (let index = 0; index < fullTileCount; index += 1) {
      pushTile(cursor, cursor + tileSize, "full");
      cursor += tileSize;
    }
    if (remainder > 0) {
      pushTile(cursor, safeLength, "cut");
    }
  } else if (anchorMode === "max_side") {
    pushTile(0, remainder, "cut");
    cursor = remainder;
    for (let index = 0; index < fullTileCount; index += 1) {
      pushTile(cursor, cursor + tileSize, "full");
      cursor += tileSize;
    }
  } else {
    const sideCut = remainder / 2;
    pushTile(0, sideCut, "cut");
    cursor = sideCut;
    for (let index = 0; index < fullTileCount; index += 1) {
      pushTile(cursor, cursor + tileSize, "full");
      cursor += tileSize;
    }
    pushTile(cursor, safeLength, "cut");
  }

  const boundaries = [...new Set([0, ...tiles.flatMap((tile) => [tile.min, tile.max]), safeLength])].sort(
    (a, b) => a - b
  );

  return {
    axis: axisName,
    length: safeLength,
    tileSize,
    anchorMode,
    tiles,
    boundaries,
    centers: tiles.map((tile) => ({
      index: tile.index,
      key: tile.key,
      center: tile.center,
      min: tile.min,
      max: tile.max,
      isCut: tile.isCut
    })),
    fullTilesCount: tiles.filter((tile) => !tile.isCut).length,
    cutTilesCount: tiles.filter((tile) => tile.isCut).length
  };
}

function buildCeilingGrid(room, ceilingLayout) {
  if (!room || !(room.length > 0) || !(room.width > 0)) {
    return null;
  }

  const tileSize = ceilingLayout?.tileSize || CEILING_TILE_SIZE;
  const xAxis = buildCeilingAxisTiles(
    room.length,
    tileSize,
    ceilingLayout?.xAnchorMode || "symmetric",
    "x"
  );
  const yAxis = buildCeilingAxisTiles(
    room.width,
    tileSize,
    ceilingLayout?.yAnchorMode || "symmetric",
    "y"
  );
  const luminaireTiles =
    ceilingLayout?.luminaireTiles instanceof Set ? ceilingLayout.luminaireTiles : new Set();
  const tiles = [];
  const tileMap = new Map();

  xAxis.tiles.forEach((xTile) => {
    yAxis.tiles.forEach((yTile) => {
      const key = `${xTile.index}:${yTile.index}`;
      const tile = {
        key,
        xIndex: xTile.index,
        yIndex: yTile.index,
        minX: xTile.min,
        maxX: xTile.max,
        minY: yTile.min,
        maxY: yTile.max,
        width: xTile.size,
        height: yTile.size,
        centerX: xTile.center,
        centerY: yTile.center,
        isCut: xTile.isCut || yTile.isCut,
        hasLuminaire: luminaireTiles.has(key)
      };

      tiles.push(tile);
      tileMap.set(key, tile);
    });
  });

  return {
    room,
    tileSize,
    xAnchorMode: xAxis.anchorMode,
    yAnchorMode: yAxis.anchorMode,
    xAxis,
    yAxis,
    tiles,
    tileMap,
    luminaireTiles,
    luminairesCount: tiles.filter((tile) => tile.hasLuminaire).length,
    fullTilesCount: tiles.filter((tile) => !tile.isCut).length,
    cutTilesCount: tiles.filter((tile) => tile.isCut).length
  };
}

// src/core/ceilingAssessment.js
function ceilingAssessmentValueKey(value) {
  return value.toFixed(6);
}

function getUniqueCoordinateValues(values) {
  const seen = new Set();
  const uniqueValues = [];

  values.forEach((value) => {
    const key = ceilingAssessmentValueKey(value);
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    uniqueValues.push(value);
  });

  return uniqueValues;
}

function findCenterMatch(axisCenters, value) {
  return axisCenters.find((center) => Math.abs(center.center - value) <= EPS) || null;
}

function buildAxisShiftCandidates(axisValues, axisCenters) {
  if (axisValues.length === 0 || axisCenters.length === 0) {
    return [];
  }

  const referenceValue = axisValues[0];
  const seenShifts = new Set();
  const candidates = [];

  axisCenters.forEach((center) => {
    const delta = center.center - referenceValue;
    const deltaKey = ceilingAssessmentValueKey(delta);

    if (seenShifts.has(deltaKey)) {
      return;
    }

    const centerByValueKey = new Map();
    let valid = true;

    axisValues.forEach((value) => {
      const shiftedValue = value + delta;
      const match = findCenterMatch(axisCenters, shiftedValue);

      if (!match) {
        valid = false;
        return;
      }

      centerByValueKey.set(ceilingAssessmentValueKey(value), match);
    });

    if (!valid) {
      return;
    }

    seenShifts.add(deltaKey);
    candidates.push({
      delta,
      centerByValueKey
    });
  });

  return candidates.sort((a, b) => Math.abs(a.delta) - Math.abs(b.delta));
}

function getMinimumClearanceForCoordinates(room, coordinates) {
  return coordinates.reduce((bestDistance, point) => {
    const nextDistance = Math.min(point.x, room.length - point.x, point.y, room.width - point.y);
    return Math.min(bestDistance, nextDistance);
  }, Number.POSITIVE_INFINITY);
}

function createIncompatibleAssessment(reasonCode, reasonText, extra = {}) {
  return {
    enabled: true,
    compatible: false,
    reasonCode,
    reasonText,
    dx: 0,
    dy: 0,
    luminaireConflict: false,
    wallClearance: null,
    appliedCoordinates: extra.appliedCoordinates || null,
    shiftApplied: false,
    visualCheckNote: "Verifier visuellement la proximite luminaire / brasseur.",
    ...extra
  };
}

function assessOptionCeilingCompatibility(option, ceilingGrid) {
  if (!ceilingGrid) {
    return {
      enabled: false,
      compatible: true,
      reasonCode: null,
      reasonText: "",
      dx: 0,
      dy: 0,
      luminaireConflict: false,
      wallClearance: option.wallClearance,
      appliedCoordinates: option.coordinates,
      shiftApplied: false,
      visualCheckNote: ""
    };
  }

  const uniqueXValues = getUniqueCoordinateValues(option.coordinates.map((point) => point.x));
  const uniqueYValues = getUniqueCoordinateValues(option.coordinates.map((point) => point.y));
  const xShiftCandidates = buildAxisShiftCandidates(uniqueXValues, ceilingGrid.xAxis.centers);
  const yShiftCandidates = buildAxisShiftCandidates(uniqueYValues, ceilingGrid.yAxis.centers);

  if (xShiftCandidates.length === 0 || yShiftCandidates.length === 0) {
    return createIncompatibleAssessment(
      "rail-alignment",
      "Aucun decalage global ne permet de faire tomber tous les centres sur des dalles du faux plafond.",
      {
        appliedCoordinates: option.coordinates
      }
    );
  }

  const combinedCandidates = [];
  xShiftCandidates.forEach((xShift) => {
    yShiftCandidates.forEach((yShift) => {
      combinedCandidates.push({
        dx: xShift.delta,
        dy: yShift.delta,
        distance: Math.hypot(xShift.delta, yShift.delta),
        xShift,
        yShift
      });
    });
  });
  combinedCandidates.sort((a, b) => a.distance - b.distance);

  let sawLuminaireConflict = false;
  let sawWallConflict = false;

  for (const combinedCandidate of combinedCandidates) {
    const appliedCoordinates = option.coordinates.map((point) => ({
      x: point.x + combinedCandidate.dx,
      y: point.y + combinedCandidate.dy
    }));
    const wallClearance = getMinimumClearanceForCoordinates(option.room, appliedCoordinates);

    if (wallClearance + EPS < option.diameter) {
      sawWallConflict = true;
      continue;
    }

    let hasLuminaireConflict = false;

    for (const point of option.coordinates) {
      const xCenter =
        combinedCandidate.xShift.centerByValueKey.get(ceilingAssessmentValueKey(point.x)) || null;
      const yCenter =
        combinedCandidate.yShift.centerByValueKey.get(ceilingAssessmentValueKey(point.y)) || null;

      if (!xCenter || !yCenter) {
        hasLuminaireConflict = true;
        break;
      }

      const tileKey = `${xCenter.index}:${yCenter.index}`;
      const tile = ceilingGrid.tileMap.get(tileKey);

      if (tile?.hasLuminaire) {
        hasLuminaireConflict = true;
        break;
      }
    }

    if (hasLuminaireConflict) {
      sawLuminaireConflict = true;
      continue;
    }

    return {
      enabled: true,
      compatible: true,
      reasonCode: null,
      reasonText:
        Math.abs(combinedCandidate.dx) > EPS || Math.abs(combinedCandidate.dy) > EPS
          ? "Les centres peuvent etre decales globalement pour tomber dans des dalles du faux plafond."
          : "Les centres theoriques tombent deja dans des dalles du faux plafond.",
      dx: combinedCandidate.dx,
      dy: combinedCandidate.dy,
      luminaireConflict: false,
      wallClearance,
      appliedCoordinates,
      shiftApplied:
        Math.abs(combinedCandidate.dx) > EPS || Math.abs(combinedCandidate.dy) > EPS,
      visualCheckNote: "Verifier visuellement la proximite luminaire / brasseur."
    };
  }

  if (sawLuminaireConflict) {
    return createIncompatibleAssessment(
      "luminaire-conflict",
      "Les positions alignees sur les dalles disponibles tombent sur une ou plusieurs dalles de luminaire existantes.",
      {
        appliedCoordinates: option.coordinates,
        luminaireConflict: true
      }
    );
  }

  if (sawWallConflict) {
    return createIncompatibleAssessment(
      "wall-conflict",
      "Le decalage necessaire pour suivre le faux plafond fait passer au moins un centre trop pres d'un mur.",
      {
        appliedCoordinates: option.coordinates
      }
    );
  }

  return createIncompatibleAssessment(
    "incompatible",
    "Le faux plafond ne permet pas de trouver une variante globale compatible sur cette trame.",
    {
      appliedCoordinates: option.coordinates
    }
  );
}

// src/core/ceilingAdaptive.js
const TILE_SAMPLE_FRACTIONS = [0.15, 0.35, 0.5, 0.65, 0.85];
const AXIS_SLOT_CANDIDATES = 9;
const AXIS_BEAM_WIDTH = 60;
const AXIS_LAYOUT_LIMIT = 18;
const DISPLAY_LIMIT = 5;

function ceilingValueKey(value) {
  return value.toFixed(6);
}

function getCandidateSignature(candidate) {
  return `${candidate.nx}x${candidate.ny}-${candidate.mountMode.id}-${Math.round(candidate.diameter * 100)}`;
}

function getFanClassForDiameter(diameter) {
  return diameter >= SMALL_FAN_LIMIT - EPS ? "large" : "small";
}

function isDiameterHeightCompatible(room, mountMode, diameter) {
  const mountDistance = mountMode.factor * diameter;
  const bladeHeight = room.height - mountDistance;
  const fanClass = getFanClassForDiameter(diameter);

  if (fanClass === "small") {
    return bladeHeight >= SMALL_SAFETY_HEIGHT - EPS && bladeHeight <= 2 * diameter + EPS;
  }

  return (
    bladeHeight >= LARGE_SAFETY_HEIGHT - EPS &&
    bladeHeight >= 0.8 * diameter - EPS &&
    bladeHeight <= 2 * diameter + EPS
  );
}

function getUniformTemplateMetrics(room, nx, ny, mountMode) {
  const cellLength = room.length / nx;
  const cellWidth = room.width / ny;
  const cellArea = cellLength * cellWidth;
  const cellShort = Math.min(cellLength, cellWidth);
  const cellLong = Math.max(cellLength, cellWidth);
  const formFactor = cellLong / cellShort;
  const coverageMinDiameter = 0.2 * Math.sqrt(cellArea);
  const coverageMaxDiameter = 0.4 * Math.sqrt(cellArea);
  const wallMaxDiameter = cellShort / 2;
  const spacingCaps = [];

  if (nx > 1) {
    spacingCaps.push(cellLength / 2.5);
  }
  if (ny > 1) {
    spacingCaps.push(cellWidth / 2.5);
  }

  const interFanMaxDiameter =
    spacingCaps.length > 0 ? Math.min(...spacingCaps) : Number.POSITIVE_INFINITY;
  const dGeoMax = Math.min(coverageMaxDiameter, wallMaxDiameter, interFanMaxDiameter);
  const intervals =
    dGeoMax > coverageMinDiameter + EPS
      ? buildHeightFeasibility(room.height, mountMode.factor, coverageMinDiameter, dGeoMax)
      : [];
  const theoreticalMaxDiameter = intervals.reduce(
    (best, interval) => Math.max(best, interval.upper),
    0
  );

  return {
    cellLength,
    cellWidth,
    cellArea,
    cellShort,
    cellLong,
    formFactor,
    coverageMinDiameter,
    coverageMaxDiameter,
    wallMaxDiameter,
    interFanMaxDiameter,
    theoreticalMaxDiameter: theoreticalMaxDiameter > EPS ? theoreticalMaxDiameter : null
  };
}

function isAxisPackingFeasible(length, count, diameter) {
  if (count === 1) {
    return length > diameter * 2 + EPS;
  }

  const minimumSpan = diameter * 2 + (count - 1) * 2.5 * diameter;
  return length > minimumSpan + EPS;
}

function buildAxisSamples(axis, length, diameter) {
  const seen = new Set();
  const samples = [];

  axis.tiles.forEach((tile) => {
    TILE_SAMPLE_FRACTIONS.forEach((fraction) => {
      const value = tile.min + tile.size * fraction;
      if (value <= diameter + EPS || value >= length - diameter - EPS) {
        return;
      }

      const key = `${tile.index}:${ceilingValueKey(value)}`;
      if (seen.has(key)) {
        return;
      }

      seen.add(key);
      samples.push({
        value: Number(value.toFixed(6)),
        tileIndex: tile.index,
        tileKey: tile.key,
        tileIsCut: tile.isCut
      });
    });
  });

  return samples.sort((a, b) => a.value - b.value);
}

function buildIdealAxisPositions(length, count) {
  return Array.from({ length: count }, (_, index) => ((index + 0.5) * length) / count);
}

function buildAxisSlotCandidates(samples, idealPositions) {
  return idealPositions.map((ideal) =>
    [...samples]
      .sort((a, b) => {
        const distanceDelta = Math.abs(a.value - ideal) - Math.abs(b.value - ideal);
        if (Math.abs(distanceDelta) > EPS) {
          return distanceDelta;
        }
        return a.value - b.value;
      })
      .slice(0, AXIS_SLOT_CANDIDATES)
  );
}

function buildAxisBoundaries(length, positions) {
  const boundaries = [0];

  for (let index = 0; index < positions.length - 1; index += 1) {
    boundaries.push((positions[index] + positions[index + 1]) / 2);
  }

  boundaries.push(length);
  return boundaries.map((value) => Number(value.toFixed(6)));
}

function getAxisCellSpans(boundaries) {
  const spans = [];

  for (let index = 0; index < boundaries.length - 1; index += 1) {
    spans.push(Number((boundaries[index + 1] - boundaries[index]).toFixed(6)));
  }

  return spans;
}

function getAxisSymmetryScore(length, positions, idealPositions) {
  const centeredPenalty = positions.reduce((sum, position, index) => {
    const mirrorIndex = positions.length - 1 - index;
    if (index > mirrorIndex) {
      return sum;
    }
    if (index === mirrorIndex) {
      return sum + Math.abs(position - length / 2) / length;
    }
    return sum + Math.abs(position + positions[mirrorIndex] - length) / length;
  }, 0);

  const idealPenalty = positions.reduce(
    (sum, position, index) => sum + Math.abs(position - idealPositions[index]) / length,
    0
  );

  const idealGap = length / positions.length;
  const gapPenalty =
    positions.length > 1
      ? positions.slice(1).reduce((sum, position, index) => {
          const gap = position - positions[index];
          return sum + Math.abs(gap - idealGap) / length;
        }, 0)
      : 0;

  return Number((centeredPenalty * 2 + idealPenalty + gapPenalty).toFixed(6));
}

function buildAxisLayouts(axis, length, count, diameter) {
  if (count <= 0) {
    return [];
  }

  const samples = buildAxisSamples(axis, length, diameter);
  if (samples.length < count) {
    return [];
  }

  const idealPositions = buildIdealAxisPositions(length, count);
  const slotCandidates = buildAxisSlotCandidates(samples, idealPositions);
  const minSpacing = count > 1 ? 2.5 * diameter : 0;
  let beam = [{ picks: [], roughScore: 0 }];

  for (let slotIndex = 0; slotIndex < count; slotIndex += 1) {
    const nextBeam = [];
    const remainingCount = count - slotIndex - 1;

    beam.forEach((partial) => {
      slotCandidates[slotIndex].forEach((candidate) => {
        const previous = partial.picks[partial.picks.length - 1];

        if (previous && candidate.value <= previous.value + minSpacing - EPS) {
          return;
        }

        const maxAllowed = length - diameter - remainingCount * minSpacing;
        if (candidate.value > maxAllowed + EPS) {
          return;
        }

        const nextPicks = [...partial.picks, candidate];
        const roughScore =
          partial.roughScore + Math.abs(candidate.value - idealPositions[slotIndex]) / length;

        nextBeam.push({
          picks: nextPicks,
          roughScore
        });
      });
    });

    const deduped = new Map();
    nextBeam
      .sort((a, b) => a.roughScore - b.roughScore)
      .forEach((state) => {
        const key = state.picks.map((pick) => ceilingValueKey(pick.value)).join("|");
        if (!deduped.has(key)) {
          deduped.set(key, state);
        }
      });

    beam = [...deduped.values()].slice(0, AXIS_BEAM_WIDTH);
    if (beam.length === 0) {
      return [];
    }
  }

  return beam
    .map((state) => {
      const positions = state.picks.map((pick) => pick.value);
      const boundaries = buildAxisBoundaries(length, positions);
      const spans = getAxisCellSpans(boundaries);
      const minClearance = Math.min(positions[0], length - positions[positions.length - 1]);
      const minSpacingValue =
        positions.length > 1
          ? positions.slice(1).reduce(
              (best, position, index) => Math.min(best, position - positions[index]),
              Number.POSITIVE_INFINITY
            )
          : null;

      return {
        positions,
        picks: state.picks,
        boundaries,
        spans,
        minClearance,
        minSpacing: minSpacingValue,
        symmetryScore: getAxisSymmetryScore(length, positions, idealPositions)
      };
    })
    .sort((a, b) => a.symmetryScore - b.symmetryScore)
    .slice(0, AXIS_LAYOUT_LIMIT);
}

function getMinimumSpacingPair(coordinates) {
  if (coordinates.length < 2) {
    return null;
  }

  let bestPair = null;
  let bestDistance = Number.POSITIVE_INFINITY;

  for (let firstIndex = 0; firstIndex < coordinates.length; firstIndex += 1) {
    for (let secondIndex = firstIndex + 1; secondIndex < coordinates.length; secondIndex += 1) {
      const distance = Math.hypot(
        coordinates[firstIndex].x - coordinates[secondIndex].x,
        coordinates[firstIndex].y - coordinates[secondIndex].y
      );

      if (distance + EPS < bestDistance) {
        bestDistance = distance;
        bestPair = [firstIndex, secondIndex];
      }
    }
  }

  return bestPair;
}

function getMinimumWallPointIndex(room, coordinates) {
  let bestIndex = 0;
  let bestClearance = Number.POSITIVE_INFINITY;

  coordinates.forEach((point, index) => {
    const clearance = Math.min(point.x, room.length - point.x, point.y, room.width - point.y);
    if (clearance + EPS < bestClearance) {
      bestClearance = clearance;
      bestIndex = index;
    }
  });

  return bestIndex;
}

function evaluateAdaptedCombination(room, ceilingGrid, nx, ny, diameter, xLayout, yLayout) {
  const fanClass = getFanClassForDiameter(diameter);
  const coordinates = [];
  const adaptedCells = [];
  let fccMin = Number.POSITIVE_INFINITY;
  let fccMax = Number.NEGATIVE_INFINITY;
  let ffMin = Number.POSITIVE_INFINITY;
  let ffMax = Number.NEGATIVE_INFINITY;
  let luminaireConflict = false;

  for (let xIndex = 0; xIndex < nx; xIndex += 1) {
    for (let yIndex = 0; yIndex < ny; yIndex += 1) {
      const tileKey = `${xLayout.picks[xIndex].tileIndex}:${yLayout.picks[yIndex].tileIndex}`;
      if (ceilingGrid.tileMap.get(tileKey)?.hasLuminaire) {
        luminaireConflict = true;
        break;
      }

      const point = {
        x: xLayout.positions[xIndex],
        y: yLayout.positions[yIndex]
      };
      const width = xLayout.spans[xIndex];
      const height = yLayout.spans[yIndex];
      const area = width * height;
      const coverageFactor = getCoverageFactorForDiameter(area, diameter);
      const formFactor = Math.max(width, height) / Math.min(width, height);

      if (!isCoverageFactorValid(coverageFactor)) {
        return null;
      }

      coordinates.push(point);
      adaptedCells.push({
        key: `${xIndex}:${yIndex}`,
        minX: xLayout.boundaries[xIndex],
        maxX: xLayout.boundaries[xIndex + 1],
        minY: yLayout.boundaries[yIndex],
        maxY: yLayout.boundaries[yIndex + 1],
        width,
        height,
        coverageFactor,
        formFactor
      });

      fccMin = Math.min(fccMin, coverageFactor);
      fccMax = Math.max(fccMax, coverageFactor);
      ffMin = Math.min(ffMin, formFactor);
      ffMax = Math.max(ffMax, formFactor);
    }

    if (luminaireConflict) {
      break;
    }
  }

  if (luminaireConflict) {
    return null;
  }

  const wallClearanceMin = coordinates.reduce((bestClearance, point) => {
    const clearance = Math.min(point.x, room.length - point.x, point.y, room.width - point.y);
    return Math.min(bestClearance, clearance);
  }, Number.POSITIVE_INFINITY);

  if (wallClearanceMin <= diameter + EPS) {
    return null;
  }

  const xSpacing = xLayout.minSpacing ?? Number.POSITIVE_INFINITY;
  const ySpacing = yLayout.minSpacing ?? Number.POSITIVE_INFINITY;
  const interFanSpacingMin = Math.min(xSpacing, ySpacing);

  if (Number.isFinite(interFanSpacingMin) && interFanSpacingMin <= 2.5 * diameter + EPS) {
    return null;
  }

  return {
    nx,
    ny,
    fanCount: nx * ny,
    diameter,
    fanClass,
    coordinates,
    adaptedCells,
    cellBoundariesX: xLayout.boundaries,
    cellBoundariesY: yLayout.boundaries,
    xPositions: xLayout.positions,
    yPositions: yLayout.positions,
    adaptedMetrics: {
      fccMin: Number(fccMin.toFixed(6)),
      fccMax: Number(fccMax.toFixed(6)),
      ffMin: Number(ffMin.toFixed(6)),
      ffMax: Number(ffMax.toFixed(6)),
      wallClearanceMin: Number(wallClearanceMin.toFixed(6)),
      interFanSpacingMin: Number.isFinite(interFanSpacingMin)
        ? Number(interFanSpacingMin.toFixed(6))
        : null,
      symmetryScore: Number((xLayout.symmetryScore + yLayout.symmetryScore).toFixed(6))
    },
    minimumWallPointIndex: getMinimumWallPointIndex(room, coordinates),
    minimumSpacingPairIndices: getMinimumSpacingPair(coordinates)
  };
}

function compareAdaptedLayouts(a, b) {
  if (Math.abs(a.adaptedMetrics.symmetryScore - b.adaptedMetrics.symmetryScore) > EPS) {
    return a.adaptedMetrics.symmetryScore - b.adaptedMetrics.symmetryScore;
  }

  if (Math.abs(b.diameter - a.diameter) > EPS) {
    return b.diameter - a.diameter;
  }

  if (Math.abs(a.adaptedMetrics.ffMax - b.adaptedMetrics.ffMax) > EPS) {
    return a.adaptedMetrics.ffMax - b.adaptedMetrics.ffMax;
  }

  if (Math.abs(b.adaptedMetrics.fccMin - a.adaptedMetrics.fccMin) > EPS) {
    return b.adaptedMetrics.fccMin - a.adaptedMetrics.fccMin;
  }

  if (a.fanCount !== b.fanCount) {
    return a.fanCount - b.fanCount;
  }

  if (a.mountMode.id !== b.mountMode.id) {
    return a.mountMode.id === "standard" ? -1 : 1;
  }

  return a.nx - b.nx || a.ny - b.ny;
}

function buildAdaptedVariantForTopology(room, ceilingGrid, nx, ny, mountMode, realDiameters) {
  const templateMetrics = getUniformTemplateMetrics(room, nx, ny, mountMode);
  const candidateDiameters = [...realDiameters]
    .filter(
      (diameter) =>
        diameter >= templateMetrics.coverageMinDiameter - EPS &&
        diameter <= templateMetrics.coverageMaxDiameter + EPS &&
        isDiameterHeightCompatible(room, mountMode, diameter) &&
        isAxisPackingFeasible(room.length, nx, diameter) &&
        isAxisPackingFeasible(room.width, ny, diameter)
    )
    .sort((a, b) => b - a);

  if (candidateDiameters.length === 0) {
    return null;
  }

  const successfulLayouts = [];

  candidateDiameters.forEach((diameter) => {
    const xLayouts = buildAxisLayouts(ceilingGrid.xAxis, room.length, nx, diameter);
    const yLayouts = buildAxisLayouts(ceilingGrid.yAxis, room.width, ny, diameter);

    if (xLayouts.length === 0 || yLayouts.length === 0) {
      return;
    }

    const layoutCandidates = [];

    xLayouts.forEach((xLayout) => {
      yLayouts.forEach((yLayout) => {
        const combination = evaluateAdaptedCombination(
          room,
          ceilingGrid,
          nx,
          ny,
          diameter,
          xLayout,
          yLayout
        );

        if (combination) {
          layoutCandidates.push({
            ...combination,
            mountMode
          });
        }
      });
    });

    if (layoutCandidates.length === 0) {
      return;
    }

    layoutCandidates.sort(compareAdaptedLayouts);
    successfulLayouts.push(layoutCandidates[0]);
  });

  if (successfulLayouts.length === 0) {
    return null;
  }

  const selectedLayout = successfulLayouts[0];
  const recommendedSmallHeight = 1.4 * selectedLayout.diameter;
  const mountDistance = mountMode.factor * selectedLayout.diameter;
  const bladeHeight = room.height - mountDistance;

  return {
    key: `adapted-${nx}x${ny}-${mountMode.id}-${Math.round(selectedLayout.diameter * 100)}`,
    placementMode: "adapted-ceiling",
    sourceStrictKey: null,
    strictReference: null,
    nx,
    ny,
    fanCount: nx * ny,
    room,
    mountMode,
    cellLength: templateMetrics.cellLength,
    cellWidth: templateMetrics.cellWidth,
    cellArea: templateMetrics.cellArea,
    cellShort: templateMetrics.cellShort,
    cellLong: templateMetrics.cellLong,
    formFactor: selectedLayout.adaptedMetrics.ffMax,
    diameter: selectedLayout.diameter,
    theoreticalMaxDiameter: templateMetrics.theoreticalMaxDiameter ?? selectedLayout.diameter,
    coverageFactor: selectedLayout.adaptedMetrics.fccMin,
    mountDistance,
    bladeHeight,
    recommendedSmallHeightMet:
      selectedLayout.fanClass === "small"
        ? bladeHeight >= recommendedSmallHeight - EPS
        : true,
    recommendedSmallHeight,
    wallClearance: selectedLayout.adaptedMetrics.wallClearanceMin,
    interFanSpacing: selectedLayout.adaptedMetrics.interFanSpacingMin,
    geometryCaps: {
      coverageMinDiameter: templateMetrics.coverageMinDiameter,
      coverageMaxDiameter: templateMetrics.coverageMaxDiameter,
      wallMaxDiameter: templateMetrics.wallMaxDiameter,
      interFanMaxDiameter: templateMetrics.interFanMaxDiameter
    },
    compatibleRealDiameters: successfulLayouts
      .map((layout) => ({
        diameter: layout.diameter,
        fanClass: layout.fanClass,
        coverageFactor: layout.adaptedMetrics.fccMin,
        coverageFactorMax: layout.adaptedMetrics.fccMax
      }))
      .sort((a, b) => a.diameter - b.diameter),
    coordinates: selectedLayout.coordinates,
    cellBoundariesX: selectedLayout.cellBoundariesX,
    cellBoundariesY: selectedLayout.cellBoundariesY,
    adaptedCells: selectedLayout.adaptedCells,
    adaptedMetrics: selectedLayout.adaptedMetrics,
    minimumWallPointIndex: selectedLayout.minimumWallPointIndex,
    minimumSpacingPairIndices: selectedLayout.minimumSpacingPairIndices,
    fanClass: selectedLayout.fanClass,
    strictAdvice:
      "Verifier la faisabilite chantier du support dans les dalles retenues et la proximite visuelle avec les luminaires.",
    ceilingGrid,
    ceilingAssessment: {
      enabled: true,
      compatible: true,
      reasonCode: "adapted",
      reasonText:
        "La trame stricte n'etait pas compatible avec le faux plafond. Une variante adaptee a ete calculee avec des centres ajustes dans les dalles disponibles.",
      dx: 0,
      dy: 0,
      luminaireConflict: false,
      wallClearance: selectedLayout.adaptedMetrics.wallClearanceMin,
      appliedCoordinates: selectedLayout.coordinates,
      shiftApplied: false,
      adjustmentMode: "individual-fit",
      adjustmentLabel: "Ajustement individuel",
      visualCheckNote: "Verifier visuellement la proximite luminaire / brasseur."
    }
  };
}

function buildAdaptedCandidatePool(room, ceilingGrid, modes, realDiameters, maxFans) {
  const pool = [];

  for (let nx = 1; nx <= maxFans; nx += 1) {
    for (let ny = 1; ny <= maxFans; ny += 1) {
      if (nx * ny > maxFans) {
        continue;
      }

      modes.forEach((mountMode) => {
        const candidate = buildAdaptedVariantForTopology(
          room,
          ceilingGrid,
          nx,
          ny,
          mountMode,
          realDiameters
        );

        if (candidate) {
          pool.push(candidate);
        }
      });
    }
  }

  return pool.sort(compareAdaptedLayouts);
}

function createStrictReference(candidate) {
  return {
    key: candidate.key,
    nx: candidate.nx,
    ny: candidate.ny,
    mountModeId: candidate.mountMode.id,
    mountLabel: candidate.mountMode.label,
    label: `${candidate.nx} × ${candidate.ny} • ${candidate.mountMode.label}`,
    cellLength: candidate.cellLength,
    cellWidth: candidate.cellWidth,
    coordinates: candidate.coordinates
  };
}

function decorateStrictCandidate(candidate, ceilingGrid) {
  return {
    ...candidate,
    placementMode: "strict",
    ceilingGrid,
    ceilingAssessment: assessOptionCeilingCompatibility(candidate, ceilingGrid)
  };
}

function decorateAdaptedDisplayCandidate(candidate, strictReference, sourceStrictKey) {
  return {
    ...candidate,
    sourceStrictKey,
    strictReference
  };
}

function isSameStrictTopology(adaptedCandidate, strictCandidate) {
  return (
    adaptedCandidate.nx === strictCandidate.nx &&
    adaptedCandidate.ny === strictCandidate.ny &&
    adaptedCandidate.mountMode.id === strictCandidate.mountMode.id
  );
}

function buildCeilingAwareDisplayCandidates(
  strictCandidates,
  room,
  modes,
  realDiameters,
  ceilingGrid,
  maxFans
) {
  if (!ceilingGrid) {
    return strictCandidates.slice(0, DISPLAY_LIMIT);
  }

  const displayCandidates = [];
  const usedSignatures = new Set();
  const usedAdaptedKeys = new Set();
  let adaptedPool = null;

  for (const strictCandidate of strictCandidates) {
    if (displayCandidates.length >= DISPLAY_LIMIT) {
      break;
    }

    const assessedStrict = decorateStrictCandidate(strictCandidate, ceilingGrid);
    const strictSignature = getCandidateSignature(assessedStrict);
    const strictReference = createStrictReference(assessedStrict);
    const strictIsUsable =
      assessedStrict.ceilingAssessment.compatible && !usedSignatures.has(strictSignature);

    if (strictIsUsable) {
      displayCandidates.push(assessedStrict);
      usedSignatures.add(strictSignature);
      continue;
    }

    if (!adaptedPool) {
      adaptedPool = buildAdaptedCandidatePool(room, ceilingGrid, modes, realDiameters, maxFans);
    }

    const replacement = adaptedPool.find(
      (candidate) =>
        isSameStrictTopology(candidate, assessedStrict) &&
        !usedAdaptedKeys.has(candidate.key) &&
        !usedSignatures.has(getCandidateSignature(candidate))
    );

    if (replacement) {
      const displayCandidate = decorateAdaptedDisplayCandidate(
        replacement,
        strictReference,
        assessedStrict.key
      );
      displayCandidates.push(displayCandidate);
      usedAdaptedKeys.add(replacement.key);
      usedSignatures.add(getCandidateSignature(displayCandidate));
      continue;
    }

    if (!usedSignatures.has(strictSignature)) {
      displayCandidates.push(assessedStrict);
      usedSignatures.add(strictSignature);
    }
  }

  return displayCandidates;
}

// src/core/calepinage.js
function getRealDiametersForIntervals(realDiameters, intervals) {
  return realDiameters
    .map((diameter) => {
      const matchingInterval = intervals.find(
        (interval) => diameter >= interval.lower - EPS && diameter <= interval.upper + EPS
      );

      if (!matchingInterval) {
        return null;
      }

      return {
        diameter,
        fanClass: matchingInterval.fanClass
      };
    })
    .filter(Boolean);
}

function getCoverageFactorForDiameter(cellArea, diameter) {
  return diameter / Math.sqrt(cellArea);
}

function isCoverageFactorValid(coverageFactor) {
  return coverageFactor >= 0.2 - EPS && coverageFactor <= 0.4 + EPS;
}

function getCompatibleRealDiameters(realDiameters, intervals, cellArea) {
  return getRealDiametersForIntervals(realDiameters, intervals)
    .map((option) => {
      const coverageFactor = getCoverageFactorForDiameter(cellArea, option.diameter);
      if (!isCoverageFactorValid(coverageFactor)) {
        return null;
      }

      return {
        diameter: option.diameter,
        fanClass: option.fanClass,
        coverageFactor
      };
    })
    .filter(Boolean);
}

/**
 * Calcule les intervalles de diametres encore compatibles avec les contraintes
 * de hauteur pour un mode de montage donne.
 */
function buildHeightFeasibility(height, mountFactor, dGeoMin, dGeoMax) {
  const lowerHeightBound = height / (2 + mountFactor);
  const intervals = [];

  const smallUpper = Math.min(
    SMALL_FAN_LIMIT - EPS,
    (height - SMALL_SAFETY_HEIGHT) / mountFactor
  );
  const smallLower = Math.max(dGeoMin, lowerHeightBound);
  if (smallUpper > smallLower + EPS) {
    intervals.push({
      fanClass: "small",
      lower: smallLower,
      upper: Math.min(dGeoMax, smallUpper)
    });
  }

  const largeUpper = Math.min(
    (height - LARGE_SAFETY_HEIGHT) / mountFactor,
    height / (0.8 + mountFactor),
    dGeoMax
  );
  const largeLower = Math.max(dGeoMin, lowerHeightBound, SMALL_FAN_LIMIT);
  if (largeUpper > largeLower + EPS) {
    intervals.push({
      fanClass: "large",
      lower: largeLower,
      upper: largeUpper
    });
  }

  return intervals.filter((interval) => interval.upper > interval.lower + EPS);
}

/**
 * Evalue une trame uniforme et retourne une option complete si elle respecte
 * toutes les contraintes geometriques et de hauteur.
 */
function evaluateCandidate(room, nx, ny, mountMode, realDiameters) {
  const cellLength = room.length / nx;
  const cellWidth = room.width / ny;
  const cellArea = cellLength * cellWidth;
  const cellShort = Math.min(cellLength, cellWidth);
  const cellLong = Math.max(cellLength, cellWidth);
  const formFactor = cellLong / cellShort;
  const coverageMinDiameter = 0.2 * Math.sqrt(cellArea);
  const coverageMaxDiameter = 0.4 * Math.sqrt(cellArea);
  const wallMaxDiameter = cellShort / 2;

  const spacings = [];
  if (nx > 1) {
    spacings.push(cellLength);
  }
  if (ny > 1) {
    spacings.push(cellWidth);
  }

  const interFanMaxDiameter =
    spacings.length > 0 ? Math.min(...spacings) / 2.5 : Number.POSITIVE_INFINITY;

  const dGeoMax = Math.min(coverageMaxDiameter, wallMaxDiameter, interFanMaxDiameter);
  if (dGeoMax <= coverageMinDiameter + EPS) {
    return null;
  }

  const intervals = buildHeightFeasibility(room.height, mountMode.factor, coverageMinDiameter, dGeoMax);
  if (intervals.length === 0) {
    return null;
  }

  const bestInterval = intervals.reduce(
    (best, current) => (!best || current.upper > best.upper ? current : best),
    null
  );
  const theoreticalMaxDiameter = bestInterval.upper;
  const compatibleRealDiameters = getCompatibleRealDiameters(realDiameters, intervals, cellArea);
  if (compatibleRealDiameters.length === 0) {
    return null;
  }

  const selectedRealDiameter = compatibleRealDiameters[compatibleRealDiameters.length - 1];
  const diameter = selectedRealDiameter.diameter;
  const mountDistance = mountMode.factor * diameter;
  const bladeHeight = room.height - mountDistance;
  const coverageFactor = selectedRealDiameter.coverageFactor;
  const recommendedSmallHeight = 1.4 * diameter;
  const recommendedSmallHeightMet =
    selectedRealDiameter.fanClass === "small"
      ? bladeHeight >= recommendedSmallHeight - EPS
      : true;

  const coordinates = [];
  for (let ix = 0; ix < nx; ix += 1) {
    for (let iy = 0; iy < ny; iy += 1) {
      coordinates.push({
        x: (ix + 0.5) * cellLength,
        y: (iy + 0.5) * cellWidth
      });
    }
  }

  return {
    key: `${nx}x${ny}-${mountMode.id}`,
    nx,
    ny,
    fanCount: nx * ny,
    room,
    mountMode,
    cellLength,
    cellWidth,
    cellArea,
    cellShort,
    cellLong,
    formFactor,
    diameter,
    theoreticalMaxDiameter,
    coverageFactor,
    mountDistance,
    bladeHeight,
    recommendedSmallHeightMet,
    recommendedSmallHeight,
    wallClearance: cellShort / 2,
    interFanSpacing: spacings.length > 0 ? Math.min(...spacings) : null,
    geometryCaps: {
      coverageMinDiameter,
      coverageMaxDiameter,
      wallMaxDiameter,
      interFanMaxDiameter
    },
    compatibleRealDiameters,
    coordinates,
    fanClass: selectedRealDiameter.fanClass,
    strictAdvice:
      "Verifier la fiche du modele retenu si son diametre nominal est proche d'une limite geometrique ou d'une limite de hauteur du guide."
  };
}

function compareCandidates(a, b) {
  if (Math.abs(b.diameter - a.diameter) > EPS) {
    return b.diameter - a.diameter;
  }

  const ffA = Math.abs(a.formFactor - 1);
  const ffB = Math.abs(b.formFactor - 1);
  if (Math.abs(ffA - ffB) > EPS) {
    return ffA - ffB;
  }

  const covA = Math.abs(0.4 - a.coverageFactor);
  const covB = Math.abs(0.4 - b.coverageFactor);
  if (Math.abs(covA - covB) > EPS) {
    return covA - covB;
  }

  if (a.mountMode.id !== b.mountMode.id) {
    return a.mountMode.id === "standard" ? -1 : 1;
  }

  return a.fanCount - b.fanCount;
}

function enumerateCandidates(room, maxFans, modes, realDiameters) {
  const candidates = [];

  for (let nx = 1; nx <= maxFans; nx += 1) {
    for (let ny = 1; ny <= maxFans; ny += 1) {
      if (nx * ny > maxFans) {
        continue;
      }

      for (const mode of modes) {
        const candidate = evaluateCandidate(room, nx, ny, mode, realDiameters);
        if (candidate) {
          candidates.push(candidate);
        }
      }
    }
  }

  return candidates.sort(compareCandidates);
}

function getFallbackFlushCandidate(room, maxFans, realDiameters) {
  const candidates = [];

  for (let nx = 1; nx <= maxFans; nx += 1) {
    for (let ny = 1; ny <= maxFans; ny += 1) {
      if (nx * ny > maxFans) {
        continue;
      }
      const candidate = evaluateCandidate(room, nx, ny, FLUSH_MODE, realDiameters);
      if (candidate) {
        candidates.push(candidate);
      }
    }
  }

  return candidates.sort(compareCandidates)[0] || null;
}

// src/ui/catalog.js
function setCatalogSelectOptions(select, options, emptyLabel, formatter = (value) => value) {
  select.innerHTML = [
    `<option value="">${escapeHtml(emptyLabel)}</option>`,
    ...options.map(
      (value) =>
        `<option value="${escapeHtml(String(value))}">${escapeHtml(formatter(value))}</option>`
    )
  ].join("");
}

function initializeCatalogFilters(dom, brasse2Models) {
  const options = getCatalogFilterOptions(brasse2Models);
  setCatalogSelectOptions(dom.catalogBrandInput, options.brands, "Toutes les marques");
  setCatalogSelectOptions(dom.catalogDiameterInput, options.diameters, "Tous les diametres", (value) => `${value} cm`);
  setCatalogSelectOptions(dom.catalogMotorInput, options.motors, "Tous les moteurs");
  setCatalogSelectOptions(dom.catalogFixationInput, options.fixations, "Toutes les fixations");
  dom.catalogSortInput.value = "diameter-asc";
}

function resetCatalogFilters(dom) {
  dom.catalogSearchInput.value = "";
  dom.catalogBrandInput.value = "";
  dom.catalogDiameterInput.value = "";
  dom.catalogMotorInput.value = "";
  dom.catalogFixationInput.value = "";
  dom.catalogSortInput.value = "diameter-asc";
}

function getCatalogFilterState(dom) {
  return {
    search: String(dom.catalogSearchInput.value || "").trim(),
    brand: dom.catalogBrandInput.value,
    diameterCm: Number.parseInt(dom.catalogDiameterInput.value, 10),
    motor: dom.catalogMotorInput.value,
    fixation: dom.catalogFixationInput.value,
    sort: dom.catalogSortInput.value || "diameter-asc"
  };
}

function renderCatalogTable(models) {
  if (models.length === 0) {
    return `
      <div class="notice warning">
        <strong>Aucun modele ne correspond aux filtres actifs.</strong>
        Ajustez les criteres ou reinitialisez les filtres pour retrouver la base complete.
      </div>
    `;
  }

  return `
    <div class="table-wrap catalog-table-wrap">
      <table>
        <thead>
          <tr>
            <th>Ref.</th>
            <th>Marque</th>
            <th>Modele</th>
            <th>Diam.</th>
            <th>Moteur</th>
            <th>Fixation</th>
            <th>Plafond/BA</th>
            <th>H test</th>
            <th>CE dir debout</th>
            <th>CFE dir debout</th>
            <th>CE moyen</th>
            <th>LwA</th>
            <th>P max</th>
          </tr>
        </thead>
        <tbody>
          ${models
            .map(
              (model) => `
                <tr>
                  <td>${escapeHtml(model.id)}</td>
                  <td>${escapeHtml(model.brand)}</td>
                  <td>${escapeHtml(model.model)}</td>
                  <td>${escapeHtml(String(model.diameterCm))}</td>
                  <td>${escapeHtml(model.motor)}</td>
                  <td>${escapeHtml(model.fixation)}</td>
                  <td>${formatNumber(model.ceilingDistanceCm, 1)} cm</td>
                  <td>${formatNumber(model.testHeightCm, 1)} cm</td>
                  <td>${formatTemp(model.ceDirDeboutMax)}</td>
                  <td>${formatNumber(model.cfeDirDeboutMax, 4)} °C/W</td>
                  <td>${formatTemp(model.ceAvgMax)}</td>
                  <td>${formatDb(model.lwaMaxDbA)}</td>
                  <td>${formatWatts(model.powerMaxW, 0)}</td>
                </tr>
              `
            )
            .join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderCatalog(dom, brasse2Models) {
  const filters = getCatalogFilterState(dom);
  const models = getFilteredCatalogModels(brasse2Models, filters);
  const activeFilters = getCatalogActiveFilterLabels(filters);

  dom.catalogSummary.innerHTML = `
    <strong>${models.length}</strong> modele${models.length > 1 ? "s" : ""} affiche${models.length > 1 ? "s" : ""}
    sur ${brasse2Models.length}
    ${activeFilters.length > 0 ? ` • Filtres actifs : ${escapeHtml(activeFilters.join(" • "))}` : ""}
  `;
  dom.catalogTableHost.innerHTML = renderCatalogTable(models);
}

// src/ui/planSvg.js
const ROOM_CORNER_RADIUS = 6;

function svgLabelBox(x, y, label, anchor = "middle", fontSize = 10.5) {
  const textWidth = Math.max(54, label.length * (fontSize * 0.6));
  let rectX = x - textWidth / 2 - 6;

  if (anchor === "start") {
    rectX = x - 6;
  } else if (anchor === "end") {
    rectX = x - textWidth - 6;
  }

  return `
    <g>
      <rect x="${rectX}" y="${y - 12}" width="${textWidth + 12}" height="18" rx="9"
        fill="rgba(255,250,242,0.96)" stroke="rgba(29,47,44,0.12)" />
      <text x="${x}" y="${y + 1.5}" text-anchor="${anchor}" font-size="${fontSize}" fill="#163531" font-weight="700">${label}</text>
    </g>
  `;
}

function svgDimensionLine(
  x1,
  y1,
  x2,
  y2,
  label,
  anchor = "middle",
  offsetX = 0,
  offsetY = -8,
  fontSize = 10.5
) {
  const labelX = (x1 + x2) / 2 + offsetX;
  const labelY = (y1 + y2) / 2 + offsetY;
  const isHorizontal = Math.abs(x2 - x1) >= Math.abs(y2 - y1);
  const startTick = isHorizontal
    ? `<line x1="${x1}" y1="${y1 - 5}" x2="${x1}" y2="${y1 + 5}" stroke="#b86d21" stroke-width="2" />`
    : `<line x1="${x1 - 5}" y1="${y1}" x2="${x1 + 5}" y2="${y1}" stroke="#b86d21" stroke-width="2" />`;
  const endTick = isHorizontal
    ? `<line x1="${x2}" y1="${y2 - 5}" x2="${x2}" y2="${y2 + 5}" stroke="#b86d21" stroke-width="2" />`
    : `<line x1="${x2 - 5}" y1="${y2}" x2="${x2 + 5}" y2="${y2}" stroke="#b86d21" stroke-width="2" />`;

  return `
    <g>
      <line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="#b86d21" stroke-width="2" />
      ${startTick}
      ${endTick}
      ${svgLabelBox(labelX, labelY, label, anchor, fontSize)}
    </g>
  `;
}

function svgFanSymbol(cx, cy, radius, index) {
  const bladeLength = radius * 0.78;
  const bladeWidth = Math.max(7, radius * 0.24);
  const hubRadius = Math.max(6, radius * 0.16);
  const bladeShape = `
    <path d="
      M ${hubRadius * 0.35} ${-bladeWidth / 2}
      Q ${bladeLength * 0.48} ${-bladeWidth * 0.72} ${bladeLength} 0
      Q ${bladeLength * 0.48} ${bladeWidth * 0.72} ${hubRadius * 0.35} ${bladeWidth / 2}
      Z
    " fill="#c9d3df" stroke="#6b7280" stroke-width="1.2" />
  `;

  return `
    <g>
      <circle cx="${cx}" cy="${cy}" r="${radius}" fill="rgba(31,79,130,0.06)" stroke="rgba(31,79,130,0.45)" stroke-width="1.6" stroke-dasharray="5 4" />
      <g transform="translate(${cx} ${cy})">
        <g transform="rotate(0)">${bladeShape}</g>
        <g transform="rotate(120)">${bladeShape}</g>
        <g transform="rotate(240)">${bladeShape}</g>
        <circle cx="0" cy="0" r="${hubRadius}" fill="#4b5563" />
        <circle cx="0" cy="0" r="${Math.max(2.6, hubRadius * 0.35)}" fill="#f9fafb" />
      </g>
      <circle cx="${cx}" cy="${cy}" r="5" fill="#111827" />
      <text x="${cx}" y="${cy + 3.8}" text-anchor="middle" font-size="9" fill="#ffffff" font-weight="700">${index + 1}</text>
    </g>
  `;
}

function getPlanCanvasMetrics(item) {
  const roomAspectRatio =
    Math.max(item.room.length, item.room.width) / Math.min(item.room.length, item.room.width);
  const rotateForFit = roomAspectRatio >= 2.2 && item.room.length > item.room.width;

  if (rotateForFit) {
    return {
      roomAspectRatio,
      rotateForFit,
      canvasWidth: 320,
      canvasHeight: 400,
      wrapMinHeight: 392
    };
  }

  if (roomAspectRatio >= 1.55) {
    return {
      roomAspectRatio,
      rotateForFit,
      canvasWidth: 360,
      canvasHeight: 290,
      wrapMinHeight: 320
    };
  }

  return {
    roomAspectRatio,
    rotateForFit,
    canvasWidth: 360,
    canvasHeight: 250,
    wrapMinHeight: 280
  };
}

function planWrapStyle(item) {
  const { wrapMinHeight } = getPlanCanvasMetrics(item);
  return `--plan-min-height:${wrapMinHeight}px;`;
}

function buildPlanGeometry(room) {
  const { roomAspectRatio, rotateForFit, canvasWidth, canvasHeight } = getPlanCanvasMetrics({ room });
  const paddingX = 28;
  const paddingY = 28;
  const displayRoomLength = rotateForFit ? room.width : room.length;
  const displayRoomHeight = rotateForFit ? room.length : room.width;
  const scale = Math.min(
    (canvasWidth - paddingX * 2) / displayRoomLength,
    (canvasHeight - paddingY * 2) / displayRoomHeight
  );
  const roomWidth = displayRoomLength * scale;
  const roomHeight = displayRoomHeight * scale;
  const roomX = (canvasWidth - roomWidth) / 2;
  const roomY = (canvasHeight - roomHeight) / 2;

  return {
    roomAspectRatio,
    rotateForFit,
    width: canvasWidth,
    height: canvasHeight,
    roomX,
    roomY,
    roomWidth,
    roomHeight,
    scale,
    displayRoomLength,
    displayRoomHeight,
    compactMode: roomAspectRatio >= 2.4,
    labelFontSize: roomAspectRatio >= 2.4 ? 9.2 : 10.5,
    compactOffset: roomAspectRatio >= 2.4 ? 2 : 0,
    projectPoint(point) {
      const displayPoint = rotateForFit ? { x: point.y, y: point.x } : point;
      return {
        x: roomX + displayPoint.x * scale,
        y: roomY + displayPoint.y * scale
      };
    },
    projectRect(rectangle) {
      const minPoint = rotateForFit
        ? { x: rectangle.minY, y: rectangle.minX }
        : { x: rectangle.minX, y: rectangle.minY };
      const maxPoint = rotateForFit
        ? { x: rectangle.maxY, y: rectangle.maxX }
        : { x: rectangle.maxX, y: rectangle.maxY };

      return {
        x: roomX + Math.min(minPoint.x, maxPoint.x) * scale,
        y: roomY + Math.min(minPoint.y, maxPoint.y) * scale,
        width: Math.abs(maxPoint.x - minPoint.x) * scale,
        height: Math.abs(maxPoint.y - minPoint.y) * scale
      };
    }
  };
}

function getRenderedCoordinates(item) {
  const ceilingAssessment = item.ceilingAssessment;

  if (ceilingAssessment?.enabled && ceilingAssessment.compatible && ceilingAssessment.appliedCoordinates) {
    return ceilingAssessment.appliedCoordinates;
  }

  return item.coordinates;
}

function renderCeilingOverlay(geometry, ceilingGrid) {
  if (!ceilingGrid) {
    return "";
  }

  return ceilingGrid.tiles
    .map((tile) => {
      const rectangle = geometry.projectRect(tile);
      const fill = tile.hasLuminaire
        ? "rgba(184,109,33,0.22)"
        : tile.isCut
          ? "rgba(29,47,44,0.05)"
          : "rgba(255,255,255,0.28)";
      const stroke = tile.hasLuminaire ? "rgba(184,109,33,0.64)" : "rgba(29,47,44,0.12)";

      return `
        <rect
          x="${rectangle.x}"
          y="${rectangle.y}"
          width="${rectangle.width}"
          height="${rectangle.height}"
          rx="6"
          fill="${fill}"
          stroke="${stroke}"
          stroke-width="${tile.hasLuminaire ? 1.3 : 1}"
        />
      `;
    })
    .join("");
}

function renderTheoreticalGhostCenters(geometry, item, displayCoordinates) {
  const assessment = item.ceilingAssessment;

  if (item.placementMode === "adapted-ceiling" && item.strictReference) {
    return item.strictReference.coordinates
      .map((point, index) => {
        const renderedPoint = geometry.projectPoint(point);
        return `
          <g>
            <circle cx="${renderedPoint.x}" cy="${renderedPoint.y}" r="4.4" fill="rgba(107,114,128,0.18)" stroke="rgba(107,114,128,0.38)" stroke-dasharray="3 3" />
            <text x="${renderedPoint.x}" y="${renderedPoint.y + 3.8}" text-anchor="middle" font-size="8.5" fill="rgba(55,65,81,0.72)" font-weight="700">${index + 1}</text>
          </g>
        `;
      })
      .join("");
  }

  if (!assessment?.compatible || !assessment.shiftApplied) {
    return "";
  }

  return item.coordinates
    .map((point, index) => {
      const renderedPoint = geometry.projectPoint(point);
      const shiftedPoint = geometry.projectPoint(displayCoordinates[index]);
      return `
        <g>
          <line
            x1="${renderedPoint.x}"
            y1="${renderedPoint.y}"
            x2="${shiftedPoint.x}"
            y2="${shiftedPoint.y}"
            stroke="rgba(107,114,128,0.5)"
            stroke-width="1.2"
            stroke-dasharray="4 4"
          />
          <circle cx="${renderedPoint.x}" cy="${renderedPoint.y}" r="3.2" fill="rgba(107,114,128,0.65)" />
        </g>
      `;
    })
    .join("");
}

function renderGridLinesFromBoundaries(
  geometry,
  boundariesX,
  boundariesY,
  stroke = "rgba(29,47,44,0.18)",
  dasharray = "6 5"
) {
  const gridLines = [];

  boundariesX.slice(1, -1).forEach((value) => {
    const x = geometry.projectPoint({ x: value, y: 0 }).x;
    gridLines.push(
      `<line x1="${x}" y1="${geometry.roomY}" x2="${x}" y2="${geometry.roomY + geometry.roomHeight}" stroke="${stroke}" stroke-dasharray="${dasharray}" />`
    );
  });

  boundariesY.slice(1, -1).forEach((value) => {
    const y = geometry.projectPoint({ x: 0, y: value }).y;
    gridLines.push(
      `<line x1="${geometry.roomX}" y1="${y}" x2="${geometry.roomX + geometry.roomWidth}" y2="${y}" stroke="${stroke}" stroke-dasharray="${dasharray}" />`
    );
  });

  return gridLines.join("");
}

function renderUniformGrid(geometry, item) {
  const boundariesX = Array.from({ length: item.nx + 1 }, (_, index) => (index * item.room.length) / item.nx);
  const boundariesY = Array.from({ length: item.ny + 1 }, (_, index) => (index * item.room.width) / item.ny);

  return renderGridLinesFromBoundaries(geometry, boundariesX, boundariesY);
}

function renderCandidateGrid(geometry, item) {
  if (item.placementMode === "adapted-ceiling") {
    return renderGridLinesFromBoundaries(
      geometry,
      item.cellBoundariesX || [0, item.room.length],
      item.cellBoundariesY || [0, item.room.width]
    );
  }

  return renderUniformGrid(geometry, item);
}

function renderStrictReferenceGrid(geometry, item) {
  if (!item.strictReference) {
    return "";
  }

  const boundariesX = Array.from(
    { length: item.strictReference.nx + 1 },
    (_, index) => (index * item.room.length) / item.strictReference.nx
  );
  const boundariesY = Array.from(
    { length: item.strictReference.ny + 1 },
    (_, index) => (index * item.room.width) / item.strictReference.ny
  );

  return renderGridLinesFromBoundaries(
    geometry,
    boundariesX,
    boundariesY,
    "rgba(107,114,128,0.28)",
    "4 4"
  );
}

function renderFans(geometry, item, displayCoordinates) {
  return displayCoordinates
    .map((point, index) => {
      const renderedPoint = geometry.projectPoint(point);
      const radius = (item.diameter / 2) * geometry.scale;
      return svgFanSymbol(renderedPoint.x, renderedPoint.y, radius, index);
    })
    .join("");
}

function getNearestWallMeasurement(room, point) {
  return [
    { axis: "x", boundary: 0, clearance: point.x },
    { axis: "x", boundary: room.length, clearance: room.length - point.x },
    { axis: "y", boundary: 0, clearance: point.y },
    { axis: "y", boundary: room.width, clearance: room.width - point.y }
  ].sort((a, b) => a.clearance - b.clearance)[0];
}

function getClosestPointToWall(room, coordinates) {
  return coordinates
    .map((point, index) => ({
      index,
      point,
      nearestWall: getNearestWallMeasurement(room, point)
    }))
    .sort((a, b) => a.nearestWall.clearance - b.nearestWall.clearance)[0];
}

function getClosestPair(coordinates) {
  if (coordinates.length < 2) {
    return null;
  }

  let best = null;
  let bestDistance = Number.POSITIVE_INFINITY;

  for (let firstIndex = 0; firstIndex < coordinates.length; firstIndex += 1) {
    for (let secondIndex = firstIndex + 1; secondIndex < coordinates.length; secondIndex += 1) {
      const distance = Math.hypot(
        coordinates[firstIndex].x - coordinates[secondIndex].x,
        coordinates[firstIndex].y - coordinates[secondIndex].y
      );

      if (distance < bestDistance) {
        bestDistance = distance;
        best = [firstIndex, secondIndex];
      }
    }
  }

  return best;
}

function renderCandidateMeasurements(geometry, candidate, displayCoordinates) {
  if (displayCoordinates.length === 0) {
    return "";
  }

  const firstRenderedPoint = geometry.projectPoint(displayCoordinates[0]);
  const radius = (candidate.diameter / 2) * geometry.scale;
  const measurements = [];

  measurements.push(
    svgDimensionLine(
      firstRenderedPoint.x - radius,
      firstRenderedPoint.y - radius - (geometry.compactMode ? 8 : 12),
      firstRenderedPoint.x + radius,
      firstRenderedPoint.y - radius - (geometry.compactMode ? 8 : 12),
      `D ${formatMeters(candidate.diameter)}`,
      "middle",
      0,
      geometry.compactMode ? -6 : -8,
      geometry.labelFontSize
    )
  );

  const closestToWall =
    Number.isInteger(candidate.minimumWallPointIndex) &&
    displayCoordinates[candidate.minimumWallPointIndex]
      ? {
          point: displayCoordinates[candidate.minimumWallPointIndex],
          nearestWall: getNearestWallMeasurement(
            candidate.room,
            displayCoordinates[candidate.minimumWallPointIndex]
          )
        }
      : getClosestPointToWall(candidate.room, displayCoordinates);
  const displayedWallClearance =
    candidate.ceilingAssessment?.wallClearance || candidate.wallClearance;
  const wallRenderedPoint = geometry.projectPoint(closestToWall.point);

  if (closestToWall.nearestWall.axis === "x") {
    const wallX =
      closestToWall.nearestWall.boundary === 0
        ? geometry.roomX
        : geometry.roomX + geometry.roomWidth;
    const lineY = Math.min(
      geometry.height - 14,
      wallRenderedPoint.y + radius + (geometry.compactMode ? 12 : 16)
    );

    measurements.push(
      svgDimensionLine(
        wallX,
        lineY,
        wallRenderedPoint.x,
        lineY,
        `Mur ${formatMeters(displayedWallClearance)}`,
        "middle",
        0,
        geometry.compactMode ? -6 : -8,
        geometry.labelFontSize
      )
    );
  } else {
    const wallY =
      closestToWall.nearestWall.boundary === 0
        ? geometry.roomY
        : geometry.roomY + geometry.roomHeight;
    const lineX = Math.min(
      geometry.width - 16,
      wallRenderedPoint.x + radius + (geometry.compactMode ? 12 : 16)
    );

    measurements.push(
      svgDimensionLine(
        lineX,
        wallY,
        lineX,
        wallRenderedPoint.y,
        `Mur ${formatMeters(displayedWallClearance)}`,
        "start",
        8 + geometry.compactOffset,
        -2,
        geometry.labelFontSize
      )
    );
  }

  if (candidate.interFanSpacing) {
    const spacingPair =
      Array.isArray(candidate.minimumSpacingPairIndices) &&
      candidate.minimumSpacingPairIndices.length === 2
        ? candidate.minimumSpacingPairIndices
        : getClosestPair(displayCoordinates);

    if (spacingPair) {
      const firstSpacingPoint = geometry.projectPoint(displayCoordinates[spacingPair[0]]);
      const secondSpacingPoint = geometry.projectPoint(displayCoordinates[spacingPair[1]]);

      measurements.push(
        svgDimensionLine(
          firstSpacingPoint.x,
          firstSpacingPoint.y,
          secondSpacingPoint.x,
          secondSpacingPoint.y,
          `Entraxe ${formatMeters(candidate.interFanSpacing)}`,
          "middle",
          0,
          geometry.compactMode ? -10 : -12,
          geometry.labelFontSize
        )
      );
    }
  }

  return measurements.join("");
}

function svgForCandidate(candidate) {
  const geometry = buildPlanGeometry(candidate.room);
  const displayCoordinates = getRenderedCoordinates(candidate);
  const fans = renderFans(geometry, candidate, displayCoordinates);
  const theoreticalGhosts = renderTheoreticalGhostCenters(geometry, candidate, displayCoordinates);
  const measurements = renderCandidateMeasurements(geometry, candidate, displayCoordinates);

  return `
    <svg viewBox="0 0 ${geometry.width} ${geometry.height}" preserveAspectRatio="xMidYMid meet" aria-hidden="true">
      <rect x="${geometry.roomX}" y="${geometry.roomY}" width="${geometry.roomWidth}" height="${geometry.roomHeight}" rx="${ROOM_CORNER_RADIUS}" fill="#faf5eb" stroke="rgba(29,47,44,0.2)" stroke-width="2.5" />
      ${renderCeilingOverlay(geometry, candidate.ceilingGrid)}
      ${renderStrictReferenceGrid(geometry, candidate)}
      ${renderCandidateGrid(geometry, candidate)}
      ${theoreticalGhosts}
      ${fans}
      ${measurements}
    </svg>
  `;
}

// src/ui/ceilingEditor.js
const CEILING_EDITOR_ROOM_CORNER_RADIUS = 6;

function buildCeilingEditorGeometry(room) {
  const { rotateForFit, canvasWidth, canvasHeight } = getPlanCanvasMetrics({ room });
  const paddingX = 28;
  const paddingY = 28;
  const displayRoomLength = rotateForFit ? room.width : room.length;
  const displayRoomHeight = rotateForFit ? room.length : room.width;
  const scale = Math.min(
    (canvasWidth - paddingX * 2) / displayRoomLength,
    (canvasHeight - paddingY * 2) / displayRoomHeight
  );
  const roomWidth = displayRoomLength * scale;
  const roomHeight = displayRoomHeight * scale;
  const roomX = (canvasWidth - roomWidth) / 2;
  const roomY = (canvasHeight - roomHeight) / 2;

  return {
    rotateForFit,
    width: canvasWidth,
    height: canvasHeight,
    scale,
    roomWidth,
    roomHeight,
    roomX,
    roomY,
    projectRect(rectangle) {
      const minX = rotateForFit ? rectangle.minY : rectangle.minX;
      const maxX = rotateForFit ? rectangle.maxY : rectangle.maxX;
      const minY = rotateForFit ? rectangle.minX : rectangle.minY;
      const maxY = rotateForFit ? rectangle.maxX : rectangle.maxY;

      return {
        x: roomX + Math.min(minX, maxX) * scale,
        y: roomY + Math.min(minY, maxY) * scale,
        width: Math.abs(maxX - minX) * scale,
        height: Math.abs(maxY - minY) * scale
      };
    }
  };
}

function renderCeilingEditorSvg(room, ceilingGrid) {
  const geometry = buildCeilingEditorGeometry(room);
  const tileShapes = ceilingGrid.tiles
    .map((tile) => {
      const rectangle = geometry.projectRect(tile);
      const fill = tile.hasLuminaire
        ? "rgba(184,109,33,0.28)"
        : tile.isCut
          ? "rgba(29,47,44,0.06)"
          : "rgba(255,255,255,0.88)";
      const stroke = tile.hasLuminaire ? "rgba(184,109,33,0.72)" : "rgba(29,47,44,0.14)";

      return `
        <rect
          x="${rectangle.x}"
          y="${rectangle.y}"
          width="${rectangle.width}"
          height="${rectangle.height}"
          rx="6"
          fill="${fill}"
          stroke="${stroke}"
          stroke-width="${tile.hasLuminaire ? 1.4 : 1}"
          data-luminaire-tile-key="${tile.key}"
          class="ceiling-editor-tile${tile.hasLuminaire ? " is-luminaire" : ""}"
        />
      `;
    })
    .join("");

  return `
    <svg viewBox="0 0 ${geometry.width} ${geometry.height}" preserveAspectRatio="xMidYMid meet" aria-hidden="true">
      <rect
        x="${geometry.roomX}"
        y="${geometry.roomY}"
        width="${geometry.roomWidth}"
        height="${geometry.roomHeight}"
        rx="${CEILING_EDITOR_ROOM_CORNER_RADIUS}"
        fill="#faf5eb"
        stroke="rgba(29,47,44,0.2)"
        stroke-width="2.5"
      />
      ${tileShapes}
    </svg>
  `;
}

function renderCeilingEditor(dom, state, room) {
  const isEnabled = !!state.ceilingLayout.enabled;

  dom.ceilingConfig.classList.toggle("hidden", !isEnabled);
  dom.ceilingAnchorXInput.value = state.ceilingLayout.xAnchorMode;
  dom.ceilingAnchorYInput.value = state.ceilingLayout.yAnchorMode;

  if (!isEnabled) {
    dom.ceilingEditorSummary.textContent = "";
    dom.ceilingEditorCanvas.innerHTML = "";
    dom.clearCeilingLuminairesButton.disabled = true;
    return null;
  }

  const ceilingGrid = buildCeilingGrid(room, state.ceilingLayout);

  if (!ceilingGrid) {
    dom.ceilingEditorSummary.textContent = "";
    dom.ceilingEditorCanvas.innerHTML = "";
    dom.clearCeilingLuminairesButton.disabled = true;
    return null;
  }

  dom.ceilingEditorSummary.innerHTML = `
    ${ceilingGrid.tiles.length} dalles visibles, dont ${ceilingGrid.cutTilesCount} dalle${ceilingGrid.cutTilesCount > 1 ? "s" : ""} recoupée${ceilingGrid.cutTilesCount > 1 ? "s" : ""}.
    ${ceilingGrid.luminairesCount} luminaire${ceilingGrid.luminairesCount > 1 ? "s" : ""} placé${ceilingGrid.luminairesCount > 1 ? "s" : ""}.
    Piece ${formatMeters(room.length)} × ${formatMeters(room.width)} (${formatSquareMeters(room.length * room.width)}).
  `;
  dom.ceilingEditorCanvas.innerHTML = renderCeilingEditorSvg(room, ceilingGrid);
  dom.clearCeilingLuminairesButton.disabled = ceilingGrid.luminairesCount === 0;

  return ceilingGrid;
}

// src/ui/reportHeader.js
function refreshReportHeader(
  dom,
  { simulationName, generatedAt = new Date() }
) {
  dom.reportKicker.textContent = `Rapport de simulation • le ${formatDateTime(generatedAt)}`;
  dom.reportTitle.textContent = simulationName;
  dom.reportContext.textContent = "";
  dom.reportContext.classList.add("hidden");

  const metaItems = [];
  dom.reportMeta.innerHTML = metaItems
    .map(
      ([label, value]) => `
        <article class="report-meta-card">
          <strong>${escapeHtml(label)}</strong>
          <span>${escapeHtml(value)}</span>
        </article>
      `
    )
    .join("");
  dom.reportMeta.classList.toggle("hidden", metaItems.length === 0);
}

function setExportAvailability(dom, enabled) {
  dom.exportPdfButton.disabled = !enabled;
}

function setExportSelectionSummary(dom, text = "") {
  if (!dom.exportSelectionSummary) {
    return;
  }

  dom.exportSelectionSummary.textContent = text;
  dom.exportSelectionSummary.classList.toggle("hidden", !text);
}

// src/ui/results.js
const modelSectionRegistry = new Map();
let nextModelSectionId = 1;

function registerModelSection(models) {
  const sectionId = `compatible-models-${nextModelSectionId}`;
  nextModelSectionId += 1;
  modelSectionRegistry.set(sectionId, models);
  return sectionId;
}

function getDefaultCompatibleModelsComparator(a, b) {
  if (a.isSelectedDiameter !== b.isSelectedDiameter) {
    return a.isSelectedDiameter ? -1 : 1;
  }
  if (Math.abs(b.compatibleOption.diameter - a.compatibleOption.diameter) > EPS) {
    return b.compatibleOption.diameter - a.compatibleOption.diameter;
  }
  return compareComfort(a, b);
}

function sortCompatibleModels(models, sortKey = "default") {
  const comparator =
    {
      default: getDefaultCompatibleModelsComparator,
      "diameter-desc": (a, b) =>
        b.diameterCm - a.diameterCm || getDefaultCompatibleModelsComparator(a, b),
      "diameter-asc": (a, b) =>
        a.diameterCm - b.diameterCm || getDefaultCompatibleModelsComparator(a, b),
      "fcc-desc": (a, b) => compareCoverage(a, b) || getDefaultCompatibleModelsComparator(a, b),
      comfort: (a, b) => compareComfort(a, b) || getDefaultCompatibleModelsComparator(a, b),
      efficiency: (a, b) =>
        compareEfficiency(a, b) || getDefaultCompatibleModelsComparator(a, b),
      acoustics: (a, b) =>
        compareAcoustics(a, b) || getDefaultCompatibleModelsComparator(a, b)
    }[sortKey] || getDefaultCompatibleModelsComparator;

  return [...models].sort(comparator);
}

function filterCompatibleModels(models, { search }) {
  const normalizedSearch = normalizeCatalogSearch(search);

  return models.filter((model) => {
    if (!normalizedSearch) {
      return true;
    }

    const haystack = normalizeCatalogSearch(
      [
        model.id,
        model.brand,
        model.model,
        model.motor,
        model.fixation,
        String(model.diameterCm)
      ].join(" ")
    );

    return haystack.includes(normalizedSearch);
  });
}

function renderModelsTableSummary(filteredCount, totalCount) {
  if (filteredCount === totalCount) {
    return `${totalCount} modele${totalCount > 1 ? "s" : ""}`;
  }

  return `${filteredCount} / ${totalCount} modele${totalCount > 1 ? "s" : ""}`;
}

function getNeutralMountSummary(items) {
  const labels = [
    ...new Set(
      items
        .map((item) => item.mountMode?.id)
        .filter(Boolean)
        .map((mountId) => (mountId === "low-profile" ? "low-profile" : "standard"))
    )
  ];

  return labels.length > 0 ? labels.join(" + ") : "Aucun";
}

function getMaxDiameterSummary(items) {
  const diameters = items.map((item) => item.diameter).filter(Number.isFinite);

  if (diameters.length === 0) {
    return {
      value: "Aucun",
      detail: "Aucun diametre reel compatible"
    };
  }

  const maxDiameter = Math.max(...diameters);

  return {
    value: `${formatDiameterCm(maxDiameter)} cm`,
    detail: "Plus grand diametre reel compatible sur les options affichees"
  };
}

function getDistinctCompatibleModels(items, brasse2Models) {
  const modelsById = new Map();

  items.forEach((item) => {
    getBrasse2ModelsForCandidate(item, brasse2Models).forEach((model) => {
      modelsById.set(model.id, model);
    });
  });

  return [...modelsById.values()];
}

function createSummaryCard(label, value, detail) {
  return `
    <article class="summary-card">
      <strong>${label}</strong>
      <span>${value}</span>
      <div class="hint">${detail}</div>
    </article>
  `;
}

function renderExportOptionToggle(optionKey, checked) {
  return `
    <label class="export-option-toggle">
      <input type="checkbox" data-export-option-key="${optionKey}" ${checked ? "checked" : ""}>
      <span>Inclure dans le PDF</span>
    </label>
  `;
}

function renderModelCard(title, model) {
  if (!model) {
    return "";
  }
  const hasCoverageFactor = Number.isFinite(model.compatibleOption.coverageFactor);

  return `
    <article class="model-card">
      <strong>${title}</strong>
      <h4>${model.brand} - ${model.model}</h4>
      <p>${model.motor} • ${model.fixation} • ${model.diameterCm} cm${model.isSelectedDiameter ? " • diametre retenu" : ""}</p>
      <div class="model-stats">
        <span>${hasCoverageFactor ? `FCC reel du calepinage: ${formatFactor(model.compatibleOption.coverageFactor)}` : `Diametre BRASSE II compatible: ${model.diameterCm} cm`}</span>
        <span>CE direct debout Vmax: ${formatTemp(model.ceDirDeboutMax)}</span>
        <span>CFE direct debout Vmax: ${formatNumber(model.cfeDirDeboutMax, 4)} °C/W</span>
        <span>LwA Vmax: ${formatDb(model.lwaMaxDbA)}</span>
        <span>${modelMountLabel(model)} (${formatNumber(model.ceilingDistanceCm, 1)} cm de base)</span>
      </div>
    </article>
  `;
}

function isAdaptedCandidate(candidate) {
  return candidate.placementMode === "adapted-ceiling";
}

function renderMetricCard(label, value, detail = "") {
  return `
    <div class="metric-card">
      <strong>${label}</strong>
      <span>${value}</span>
      ${detail ? `<small>${detail}</small>` : ""}
    </div>
  `;
}

function formatAdaptedRange(min, max) {
  if (!Number.isFinite(min) || !Number.isFinite(max)) {
    return "—";
  }

  if (Math.abs(max - min) <= EPS) {
    return formatFactor(min);
  }

  return `${formatFactor(min)} - ${formatFactor(max)}`;
}

function getAdaptedWorstFactorLabel(candidate) {
  return Number.isFinite(candidate.adaptedMetrics?.ffMax)
    ? formatFactor(candidate.adaptedMetrics.ffMax)
    : "—";
}

function formatCeilingShiftLabel(assessment) {
  if (assessment?.adjustmentLabel) {
    return assessment.adjustmentLabel;
  }

  if (!assessment?.shiftApplied) {
    return "Aucun decalage";
  }

  return `${formatNumber(assessment.dx * 100, 0)} cm / ${formatNumber(assessment.dy * 100, 0)} cm`;
}

function renderCeilingDetailItems(item) {
  const assessment = item.ceilingAssessment;

  if (!assessment?.enabled) {
    return "";
  }

  return `
    ${
      item.strictReference
        ? `
          <div class="detail-item">
            <strong>Trame stricte reference</strong>
            <span>${item.strictReference.label}</span>
          </div>
        `
        : ""
    }
    <div class="detail-item">
      <strong>Compatibilite faux plafond</strong>
      <span>${assessment.compatible ? "Compatible" : "Non compatible"}</span>
    </div>
    <div class="detail-item">
      <strong>Decalage de trame</strong>
      <span>${formatCeilingShiftLabel(assessment)}</span>
    </div>
    <div class="detail-item">
      <strong>Conflit luminaire</strong>
      <span>${assessment.luminaireConflict ? "Oui" : "Non"}</span>
    </div>
  `;
}

function renderCeilingNotice(item) {
  const assessment = item.ceilingAssessment;

  if (!assessment?.enabled) {
    return "";
  }

  if (isAdaptedCandidate(item)) {
    return `
      <div class="notice warning">
        <strong>Option adaptee faux plafond.</strong>
        ${assessment.reasonText}
        ${
          item.strictReference
            ? ` Reference stricte remplacee : ${item.strictReference.label}.`
            : ""
        }
        ${assessment.visualCheckNote ? ` ${assessment.visualCheckNote}` : ""}
      </div>
    `;
  }

  return `
    <div class="notice ${assessment.compatible ? "warning" : "danger"}">
      <strong>${assessment.compatible ? "Lecture faux plafond." : "Faux plafond non compatible."}</strong>
      ${assessment.reasonText}
      ${assessment.visualCheckNote ? ` ${assessment.visualCheckNote}` : ""}
    </div>
  `;
}

function renderModelsTable(models) {
  if (models.length === 0) {
    return `
      <div class="notice warning">
        <strong>Aucun modele ne correspond aux filtres actifs.</strong>
        Elargissez la recherche ou reinitialisez les filtres de cette option.
      </div>
    `;
  }

  return `
    <div class="table-wrap">
      <table>
        <thead>
          <tr>
            <th>Diam.</th>
            <th>FCC reel</th>
            <th>Marque</th>
            <th>Modele</th>
            <th>Moteur</th>
            <th>Fixation</th>
            <th>Plafond/BA</th>
            <th>CE dir debout Vmax</th>
            <th>CFE dir debout Vmax</th>
            <th>CE moyen Vmax</th>
            <th>LwA Vmax</th>
            <th>Lecture montage</th>
          </tr>
        </thead>
        <tbody>
          ${models
            .map(
              (model) => `
                <tr>
                  <td>${model.diameterCm}</td>
                  <td>${Number.isFinite(model.compatibleOption.coverageFactor) ? formatFactor(model.compatibleOption.coverageFactor) : "—"}</td>
                  <td>${model.brand}</td>
                  <td>${model.model}</td>
                  <td>${model.motor}</td>
                  <td>${model.fixation}</td>
                  <td>${formatNumber(model.ceilingDistanceCm, 1)} cm</td>
                  <td>${formatTemp(model.ceDirDeboutMax)}</td>
                  <td>${formatNumber(model.cfeDirDeboutMax, 4)} °C/W</td>
                  <td>${formatTemp(model.ceAvgMax)}</td>
                  <td>${formatDb(model.lwaMaxDbA)}</td>
                  <td>${modelMountLabel(model)}</td>
                </tr>
              `
            )
            .join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderModelsToolbar(sectionId, models) {
  return `
    <div class="models-toolbar">
      <div class="field">
        <label for="${sectionId}-search">Recherche</label>
        <input id="${sectionId}-search" type="search" placeholder="Ref., marque, modele" data-model-search>
      </div>
      <div class="field">
        <label for="${sectionId}-sort">Tri</label>
        <select id="${sectionId}-sort" data-model-sort>
          <option value="default">Ordre recommande</option>
          <option value="fcc-desc">FCC reel decroissant</option>
          <option value="comfort">Confort</option>
          <option value="efficiency">Efficacite</option>
          <option value="acoustics">Acoustique</option>
          <option value="diameter-desc">Diametre decroissant</option>
          <option value="diameter-asc">Diametre croissant</option>
        </select>
      </div>
      <p class="models-toolbar-summary" data-models-summary>${renderModelsTableSummary(models.length, models.length)}</p>
    </div>
  `;
}

function renderModelsTablePanel(sectionId, models) {
  return `
    <div class="models-table-panel" data-model-section="${sectionId}">
      ${renderModelsToolbar(sectionId, models)}
      <div data-models-table-host>${renderModelsTable(sortCompatibleModels(models))}</div>
    </div>
  `;
}

function updateModelsTableSection(sectionElement) {
  if (!sectionElement) {
    return;
  }

  const sectionId = sectionElement.dataset.modelSection;
  const models = modelSectionRegistry.get(sectionId) || [];
  const search = sectionElement.querySelector("[data-model-search]")?.value || "";
  const sort = sectionElement.querySelector("[data-model-sort]")?.value || "default";

  const filteredModels = filterCompatibleModels(models, {
    search
  });
  const sortedModels = sortCompatibleModels(filteredModels, sort);
  const host = sectionElement.querySelector("[data-models-table-host]");
  const summary = sectionElement.querySelector("[data-models-summary]");

  if (host) {
    host.innerHTML = renderModelsTable(sortedModels);
  }
  if (summary) {
    summary.textContent = renderModelsTableSummary(filteredModels.length, models.length);
  }
}

function bindResultsInteractions(dom) {
  if (dom.resultsList.dataset.resultsInteractionsBound === "true") {
    return;
  }

  const refreshFromEvent = (event) => {
    const target = event.target;
    if (
      !target ||
      !target.matches?.(
        "[data-model-search], [data-model-sort]"
      )
    ) {
      return;
    }

    updateModelsTableSection(target.closest("[data-model-section]"));
  };

  dom.resultsList.addEventListener("input", refreshFromEvent);
  dom.resultsList.addEventListener("change", refreshFromEvent);
  dom.resultsList.dataset.resultsInteractionsBound = "true";
}

function resetResultsModelSections() {
  modelSectionRegistry.clear();
  nextModelSectionId = 1;
}

function renderBrasse2Section(candidate, brasse2Models, realDiameters) {
  const models = getBrasse2ModelsForCandidate(candidate, brasse2Models);

  if (models.length === 0) {
    return `
      <section class="models-shell">
        <div>
          <h4 class="section-title">Modeles pré-sélectionnés</h4>
          <p class="section-subtitle" style="margin-bottom:0;">
            Filtrage sur les diametres BRASSE II admissibles pour ce calepinage.
          </p>
        </div>
        <div class="notice warning">
          <strong>Aucun modele BRASSE II compatible.</strong>
          La base embarquee couvre ici les diametres disponibles dans BRASSE II :
          <code>${formatDiameterList(realDiameters)}</code>.
        </div>
      </section>
    `;
  }

  const sectionId = registerModelSection(models);
  const modelPicks = buildModelPicks(models);

  return `
    <section class="models-shell">
      <div>
        <h4 class="section-title">Modeles pré-sélectionnés</h4>
        <p class="section-subtitle" style="margin-bottom:0;">
          Filtrage sur tous les diametres admissibles. Les cartes ci-dessous lisent le meilleur FCC du calepinage,
          puis les indicateurs BRASSE a Vmax : confort direct debout, efficacite directe debout et acoustique.
        </p>
      </div>

      <div class="models-grid">
        ${modelPicks.map((pick) => renderModelCard(pick.title, pick.model)).join("")}
      </div>

      <details class="models-details">
        <summary>Voir tous les modeles BRASSE II compatibles (${models.length})</summary>
        ${renderModelsTablePanel(sectionId, models)}
      </details>
    </section>
  `;
}

function candidateCard(candidate, rank, brasse2Models, realDiameters, selectedOptionKeys) {
  const warnings = getCandidateWarnings(candidate);
  const isSelectedForExport = selectedOptionKeys.has(candidate.key);
  const adapted = isAdaptedCandidate(candidate);
  const subtitle = adapted
    ? `${candidate.fanCount} brasseur${candidate.fanCount > 1 ? "s" : ""} en option adaptee faux plafond sur une trame ${candidate.nx} × ${candidate.ny}.${candidate.strictReference ? ` Reference stricte remplacee : ${candidate.strictReference.label}.` : ""}`
    : `${candidate.fanCount} brasseur${candidate.fanCount > 1 ? "s" : ""} centre${candidate.fanCount > 1 ? "s" : ""} dans des cellules de ${formatMeters(candidate.cellLength)} × ${formatMeters(candidate.cellWidth)}, avec un diametre BRASSE II retenu de ${formatMeters(candidate.diameter)}.`;
  const metricCards = adapted
    ? [
        renderMetricCard(
          "Diametre réel retenu",
          formatMeters(candidate.diameter),
          "Option adaptee faux plafond"
        ),
        renderMetricCard(
          "Trame finale",
          `${candidate.nx} × ${candidate.ny}`,
          `${candidate.fanCount} brasseur${candidate.fanCount > 1 ? "s" : ""}`
        ),
        renderMetricCard(
          "FCC recalcule",
          formatAdaptedRange(candidate.adaptedMetrics?.fccMin, candidate.adaptedMetrics?.fccMax),
          `Pire cas : ${formatFactor(candidate.adaptedMetrics?.fccMin ?? candidate.coverageFactor)}`
        ),
        renderMetricCard(
          "Facteur de forme recalcule",
          formatAdaptedRange(candidate.adaptedMetrics?.ffMin, candidate.adaptedMetrics?.ffMax),
          `Pire cas : ${getAdaptedWorstFactorLabel(candidate)}`
        )
      ].join("")
    : [
        renderMetricCard("Diametre réel retenu", formatMeters(candidate.diameter)),
        renderMetricCard("Diametre theorique max", formatMeters(candidate.theoreticalMaxDiameter)),
        renderMetricCard("Facteur de forme", formatFactor(candidate.formFactor)),
        renderMetricCard("FCC reel", formatFactor(candidate.coverageFactor))
      ].join("");

  return `
    <article class="result-card">
      <div class="result-head">
        <div>
          <h3 class="result-title">Option ${rank}</h3>
          <p class="result-subtitle">${subtitle}</p>
        </div>
        ${renderExportOptionToggle(candidate.key, isSelectedForExport)}
      </div>

      <div class="result-grid">
        <div class="plan-wrap" style="${planWrapStyle(candidate)}">${svgForCandidate(candidate)}</div>

        <div class="stack">
          <div class="metric-grid">${metricCards}</div>

          <div class="detail-list">
            <div class="detail-item">
              <strong>Montage</strong>
              <span>${candidate.mountMode.label}</span>
            </div>
            <div class="detail-item">
              <strong>Hauteur sous pales</strong>
              <span class="detail-value-stack">
                <span>${formatMeters(candidate.bladeHeight)}</span>
                <span class="detail-subtext">Plafond-pales: ${formatMeters(candidate.mountDistance)}</span>
              </span>
            </div>
            <div class="detail-item">
              <strong>Murs</strong>
              <span>Centre vers mur le plus proche: ${formatMeters(candidate.wallClearance)} &gt; ${formatMeters(candidate.diameter)}</span>
            </div>
            <div class="detail-item">
              <strong>Entre brasseurs</strong>
              <span>${candidate.interFanSpacing ? `${formatMeters(candidate.interFanSpacing)} &gt; ${formatNumber(2.5, 1)} × D` : "Non applicable (un seul brasseur)"}</span>
            </div>
            ${
              adapted
                ? `
                  <div class="detail-item">
                    <strong>FCC pire cas</strong>
                    <span>${formatFactor(candidate.adaptedMetrics?.fccMin ?? candidate.coverageFactor)}</span>
                  </div>
                  <div class="detail-item">
                    <strong>Facteur de forme pire cas</strong>
                    <span>${getAdaptedWorstFactorLabel(candidate)}</span>
                  </div>
                `
                : ""
            }
            <div class="detail-item detail-item-stack">
              <strong>Diametres BRASSE II admissibles (FCC &gt;= 0,2)</strong>
              <span>${candidate.compatibleRealDiameters.map((option) => formatDiameterCm(option.diameter)).join(", ")}</span>
            </div>
            ${renderCeilingDetailItems(candidate)}
          </div>
        </div>
      </div>

      ${warnings.length > 0 ? `
        <div class="notice warning">
          <strong>Point d'attention.</strong>
          ${warnings.join(" ")}
        </div>
      ` : ""}

      ${renderCeilingNotice(candidate)}

      ${renderBrasse2Section(candidate, brasse2Models, realDiameters)}

    </article>
  `;
}

function renderSummary(dom, room, candidates, brasse2Models, totalOptionCount = candidates.length) {
  const roomArea = room.length * room.width;
  const compatibleModels = getDistinctCompatibleModels(candidates, brasse2Models);
  const diameterSummary = getMaxDiameterSummary(candidates);
  const mountSummary = getNeutralMountSummary(candidates);

  dom.summaryGrid.innerHTML = [
    createSummaryCard(
      "Piece",
      `${formatMeters(room.length)} × ${formatMeters(room.width)}`,
      `${formatSquareMeters(roomArea)} - HSP ${formatMeters(room.height)}`
    ),
    createSummaryCard(
      "Options valides",
      `${totalOptionCount}`,
      `Montages visibles : ${mountSummary}`
    ),
    createSummaryCard(
      "Diametre max",
      diameterSummary.value,
      diameterSummary.detail
    ),
    createSummaryCard(
      "Base BRASSE II",
      compatibleModels.length > 0
        ? `${compatibleModels.length} modeles`
        : "Aucun modele compatible",
      "Compatibles avec les options affichees"
    )
  ].join("");
  dom.highlights.innerHTML = "";
}

function renderStatusNote(
  dom,
  room,
  candidates,
  fallbackFlush,
  modes,
  realDiameters
) {
  const notes = [];
  const heightRequirementMessage = buildHeightDiameterRequirementMessage(room, modes, realDiameters);

  if (candidates.length > 0) {
    const best = candidates[0];
    if (best.mountMode.id === "low-profile") {
      notes.push(`
        <div class="notice warning">
          <strong>Le meilleur cas passe en low-profile.</strong>
          Le guide indique alors une baisse de vitesse d'air d'environ 15 %. Une variante standard est egalement
          affichee plus bas si elle existe. Le diametre retenu est choisi ici parmi les diametres reels disponibles.
        </div>
      `);
    }
  }

  if (fallbackFlush && candidates.length === 0) {
    notes.push(`
      <div class="notice danger">
        <strong>Aucune solution standard ou low-profile n'a ete trouvee.</strong>
        Un montage flush pourrait rouvrir une piste jusqu'a ${formatMeters(fallbackFlush.diameter)}, mais le guide
        annonce alors une perte de performance superieure a 40 % et demande de l'eviter au maximum.
        ${heightRequirementMessage}
      </div>
    `);
  }

  if (!fallbackFlush && candidates.length === 0) {
    notes.push(`
      <div class="notice danger">
        <strong>Aucun diametre réel de la liste testée ne passe dans ce local.</strong>
        L'outil a teste ${formatDiameterList(realDiameters)} avec les regles BRASSE
        de FCC, de distances et de hauteur.
        ${heightRequirementMessage}
      </div>
    `);
  }

  dom.statusNote.innerHTML = notes.join("");
}

function renderResults(dom, candidates, brasse2Models, realDiameters, selectedOptionKeys = []) {
  resetResultsModelSections();
  const selectedOptionKeySet = new Set(selectedOptionKeys);
  dom.resultsList.innerHTML = candidates
    .slice(0, 5)
    .map((candidate, index) =>
      candidateCard(candidate, index + 1, brasse2Models, realDiameters, selectedOptionKeySet)
    )
    .join("");
}

// src/report/pdf.js
function isAdaptedCandidate(option) {
  return option.placementMode === "adapted-ceiling";
}

function formatCandidateCoverageSummary(option) {
  if (!isAdaptedCandidate(option)) {
    return formatFactor(option.coverageFactor);
  }

  return `${formatFactor(option.adaptedMetrics.fccMin)} a ${formatFactor(option.adaptedMetrics.fccMax)}`;
}

function formatCandidateCoverageWorst(option) {
  return formatFactor(
    isAdaptedCandidate(option) ? option.adaptedMetrics.fccMin : option.coverageFactor
  );
}

function formatCandidateFormFactorSummary(option) {
  if (!isAdaptedCandidate(option)) {
    return formatFactor(option.formFactor);
  }

  return `${formatFactor(option.adaptedMetrics.ffMin)} a ${formatFactor(option.adaptedMetrics.ffMax)}`;
}

function formatCandidateFormFactorWorst(option) {
  return formatFactor(
    isAdaptedCandidate(option) ? option.adaptedMetrics.ffMax : option.formFactor
  );
}

function getOptionHeading(option) {
  if (!isAdaptedCandidate(option)) {
    return `${option.nx} × ${option.ny} cellules`;
  }

  return `${option.nx} × ${option.ny} - option adaptee faux plafond`;
}

function getOptionSubheading(option) {
  const base = `${option.fanCount} brasseur${option.fanCount > 1 ? "s" : ""} • ${option.mountMode.label}`;

  if (!isAdaptedCandidate(option) || !option.strictReference) {
    return base;
  }

  return `${base} • reference stricte : ${option.strictReference.label}`;
}

function getAllReportOptions(state) {
  if (!state) {
    return [];
  }

  if (state.kind === "uniformity-ok") {
    return state.candidates || [];
  }

  return [];
}

function getReportOptionNumber(state, option) {
  const index = getAllReportOptions(state).findIndex((item) => item.key === option.key);
  return index >= 0 ? index + 1 : null;
}

function getDistinctCompatibleModels(options, brasse2Models) {
  const modelsById = new Map();

  options.forEach((option) => {
    getBrasse2ModelsForCandidate(option, brasse2Models).forEach((model) => {
      modelsById.set(model.id, model);
    });
  });

  return [...modelsById.values()];
}

function getMaxDiameterSummary(options) {
  const diameters = options.map((option) => option.diameter).filter(Number.isFinite);

  if (diameters.length === 0) {
    return {
      value: "Aucun",
      detail: "Aucun diametre reel compatible"
    };
  }

  const maxDiameter = Math.max(...diameters);
  return {
    value: `${formatDiameterCm(maxDiameter)} cm`,
    detail: "Plus grand diametre reel des options exportees"
  };
}

function renderReportWarningList(items) {
  if (!items || items.length === 0) {
    return "";
  }

  return `
    <div class="report-note report-note-warning">
      <strong>Points d'attention</strong>
      <ul>
        ${items.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}
      </ul>
    </div>
  `;
}

function renderReportSummaryCards(items) {
  return `
    <div class="report-summary-grid">
      ${items
        .map(
          ([label, value, detail]) => `
            <article class="report-summary-card">
              <strong>${escapeHtml(label)}</strong>
              <span>${escapeHtml(value)}</span>
              <small>${escapeHtml(detail)}</small>
            </article>
          `
        )
        .join("")}
    </div>
  `;
}

function renderReportMetricGrid(items) {
  return `
    <div class="report-metrics">
      ${items
        .map(
          ([label, value]) => `
            <article class="report-metric">
              <strong>${escapeHtml(label)}</strong>
              <span>${escapeHtml(value)}</span>
            </article>
          `
        )
        .join("")}
    </div>
  `;
}

function renderReportTable(headers, rows, compact = false) {
  return `
    <table class="report-table${compact ? " compact" : ""}">
      <thead>
        <tr>
          ${headers.map((header) => `<th>${escapeHtml(header)}</th>`).join("")}
        </tr>
      </thead>
      <tbody>
        ${rows
          .map(
            (row) => `
              <tr>
                ${row.map((cell) => `<td>${escapeHtml(cell)}</td>`).join("")}
              </tr>
            `
          )
          .join("")}
      </tbody>
    </table>
  `;
}

function renderModelHighlights(option, brasse2Models) {
  const highlights = getReportModelHighlights(option, brasse2Models);
  if (highlights.length === 0) {
    return `
      <div class="report-note">
        <strong>Modeles pre-selectionnes</strong>
        <p>Aucun modele compatible dans la base BRASSE II embarquee sur les diametres admissibles de cette option.</p>
      </div>
    `;
  }

  const rows = highlights.map((entry) => [
    entry.title,
    `${entry.model.brand} ${entry.model.model}`,
    `${entry.model.diameterCm} cm`,
    Number.isFinite(entry.model.compatibleOption.coverageFactor)
      ? formatFactor(entry.model.compatibleOption.coverageFactor)
      : "—",
    formatTemp(entry.model.ceDirDeboutMax),
    `${formatNumber(entry.model.cfeDirDeboutMax, 4)} °C/W`,
    formatDb(entry.model.lwaMaxDbA)
  ]);

  return `
    <section class="report-section">
      <h3>Modeles pre-selectionnes</h3>
      ${renderReportTable(
        ["Lecture", "Marque / modele", "Diam.", "FCC", "CE dir.", "CFE dir.", "LwA"],
        rows,
        true
      )}
    </section>
  `;
}

function renderStudySummarySection(state, selectedOptions, brasse2Models) {
  const roomArea = state.room.length * state.room.width;
  const compatibleModels = getDistinctCompatibleModels(selectedOptions, brasse2Models);
  const maxDiameterSummary = getMaxDiameterSummary(selectedOptions);
  const baseCards = [
    [
      "Piece",
      `${formatMeters(state.room.length)} × ${formatMeters(state.room.width)}`,
      `${formatSquareMeters(roomArea)} - HSP ${formatMeters(state.room.height)}`
    ],
    [
      "Diametre max",
      maxDiameterSummary.value,
      maxDiameterSummary.detail
    ],
    [
      "Base BRASSE II",
      compatibleModels.length > 0 ? `${compatibleModels.length} modeles` : "Aucun modele",
      "Compatibles avec les options exportees"
    ]
  ];

  return `
    <section class="report-block">
      <h2>Synthese de la piece etudiee</h2>
      ${renderReportSummaryCards(baseCards)}
    </section>
  `;
}

function renderSelectedOptionsOverview(state, selectedOptions) {
  if (selectedOptions.length === 0) {
    return `
      <section class="report-block">
        <h2>Synthese de ou des option(s) retenue(s) :</h2>
        <div class="report-note report-note-warning">
          <strong>Aucune option selectionnee</strong>
          <p>Cochez au moins une option dans l'outil pour l'inclure dans le rapport PDF.</p>
        </div>
      </section>
    `;
  }

  if (state.kind === "uniformity-ok") {
    const rows = selectedOptions.map((option) => [
      `Option ${getReportOptionNumber(state, option)}`,
      isAdaptedCandidate(option) ? `${option.nx} × ${option.ny} adaptee` : `${option.nx} × ${option.ny}`,
      formatMeters(option.diameter),
      option.mountMode.label,
      formatCandidateCoverageWorst(option)
    ]);

    return `
      <section class="report-block">
        <h2>Synthese de ou des option(s) retenue(s) :</h2>
        ${renderReportTable(
          ["Option", "Trame", "Diametre reel", "Montage", "FCC pire cas"],
          rows,
          true
        )}
      </section>
    `;
  }
}

function renderUniformityOptionPage(state, option, brasse2Models) {
  const optionNumber = getReportOptionNumber(state, option);

  return `
    <section class="report-page report-option-page">
      <div class="report-section-head">
        <p class="report-section-kicker">Option ${optionNumber}</p>
        <h2>${escapeHtml(getOptionHeading(option))}</h2>
        <p>${escapeHtml(getOptionSubheading(option))}</p>
      </div>

      ${renderReportMetricGrid([
        ["Diametre reel retenu", formatMeters(option.diameter)],
        ["Diametre theorique max", formatMeters(option.theoreticalMaxDiameter)],
        [
          isAdaptedCandidate(option) ? "Facteur de forme recalcule" : "Facteur de forme",
          formatCandidateFormFactorSummary(option)
        ],
        [
          isAdaptedCandidate(option) ? "FCC recalcule" : "FCC reel",
          formatCandidateCoverageSummary(option)
        ],
        ["Hauteur sous pales", formatMeters(option.bladeHeight)],
        ["Plafond-pales", formatMeters(option.mountDistance)]
      ])}

      <div class="report-plan-block">
        <div class="report-plan">${svgForCandidate(option)}</div>
        <div class="report-side">
          ${renderReportTable(
            ["Lecture", "Valeur"],
            [
              ["Montage", option.mountMode.label],
              [
                "Trame",
                isAdaptedCandidate(option)
                  ? `${option.nx} × ${option.ny} adaptee`
                  : `${formatMeters(option.cellLength)} × ${formatMeters(option.cellWidth)}`
              ],
              ...(option.strictReference
                ? [["Reference stricte", option.strictReference.label]]
                : []),
              ["Mur limitant", `${formatMeters(option.wallClearance)} > ${formatMeters(option.diameter)}`],
              [
                "Entraxe mini",
                option.interFanSpacing
                  ? `${formatMeters(option.interFanSpacing)} > 2,5 × D`
                  : "Non applicable"
              ],
              ...(isAdaptedCandidate(option)
                ? [
                    [
                      "FCC pire cas",
                      formatCandidateCoverageWorst(option)
                    ],
                    [
                      "Facteur de forme pire cas",
                      formatCandidateFormFactorWorst(option)
                    ]
                  ]
                : []),
              ["Diametres admissibles", formatDiameterCmList(option.compatibleRealDiameters)]
            ],
            true
          )}
          ${renderReportWarningList(getCandidateWarnings(option))}
        </div>
      </div>

      ${renderModelHighlights(option, brasse2Models)}
    </section>
  `;
}

function renderReportFirstPage(state, selectedOptions, brasse2Models) {
  return `
    <section class="report-page report-first-page">
      <header class="report-cover">
        <p class="report-cover-kicker">Rapport de simulation • le ${escapeHtml(
          formatDateTime(state.generatedAt)
        )}</p>
        <h1>${escapeHtml(state.simulationName)}</h1>
        <p class="report-cover-lead">
          Synthese de la piece etudiee et des options selectionnees pour l'export PDF.
        </p>
      </header>

      ${renderStudySummarySection(state, selectedOptions, brasse2Models)}
      ${renderSelectedOptionsOverview(state, selectedOptions)}
    </section>
  `;
}

function renderEmptyOrInvalidReport(state) {
  const roomBlock =
    state.room && Number.isFinite(state.room.length)
      ? renderReportSummaryCards([
          [
            "Piece",
            `${formatMeters(state.room.length)} × ${formatMeters(state.room.width)}`,
            `${formatSquareMeters(state.room.length * state.room.width)} - HSP ${formatMeters(
              state.room.height
            )}`
          ]
        ])
      : "";

  let title = "Calcul impossible";
  let text =
    "Les donnees saisies ne permettent pas de produire un rapport de calepinage exploitable.";

  if (state.kind === "uniformity-empty") {
    title = "Aucune solution compatible";
    text =
      "Aucun cas standard ou low-profile n'a pu etre valide avec les regles BRASSE de FCC, de distances et de hauteur.";
  }

  return `
    <section class="report-page report-first-page">
      <header class="report-cover">
        <p class="report-cover-kicker">Rapport de simulation • le ${escapeHtml(
          formatDateTime(state.generatedAt)
        )}</p>
        <h1>${escapeHtml(state.simulationName)}</h1>
      </header>
      ${roomBlock}
      <section class="report-block">
        <h2>Conclusion</h2>
        <div class="report-note report-note-warning">
          <strong>${escapeHtml(title)}</strong>
          <p>${escapeHtml(text)}</p>
        </div>
        ${
          state.issues?.length
            ? `
              <div class="report-note" style="margin-top: 10px;">
                <strong>Points releves</strong>
                <ul>
                  ${state.issues.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}
                </ul>
              </div>
            `
            : ""
        }
      </section>
    </section>
  `;
}

